INSERT INTO membership_tiers (name, description, benefits, price_label, position, is_default) VALUES ('Full Membership', 'For employer organisations committed to best practice in graduate recruitment and development.', ARRAY['Includes one primary representative','Additional representatives can be added','Access to AAGE events, insights and member benefits']::text[], 'Primary $450/year ex GST; additional $110/person/year', 1, true);
