INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('index', 'Home', '<div><div><div><div><table><tr><td><div><div><div ><div><span><br></span><span>Welcome to the home of the early careers industry in Australia</span></div></div><div ><div><br></div></div></div></div></td></tr></table></div></div></div></div><!-- /content zone --><!-- footer zone --><div><div><div><div><table><tr><td><div><div><div ><div><p>Relationships</p></div></div><div ><div><p>Join our supportive community and connect with employers, universities, industry partners and talent.</p></div></div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/relationships-aage-homepage-7de483d7-d9f0ac23.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/insights-aage-homepage-c62ddfe9-001aef3c.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>Insights</p></div></div><div ><div><p>Make better informed decisions thanks to exclusive insights, information and market intelligence produced for AAGE members.&nbsp;</p></div></div><div ><div><a href="/page.html?slug=knowledge" target="_blank" rel="noopener">AAGE Research</a></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p>Expertise</p></div></div><div ><div><p>Share and recognise industry best practice in early careers talent programs.</p></div></div><div ><div><a href="/page.html?slug=best-practice" target="_blank" rel="noopener">AAGE Awards</a></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/homepage-gala-dinner-414bdb2c-f9951a9f.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/events-aage-homepage-b1455a51-eac75c06.png" alt="" title="" loading="lazy"><br></p></div></div><div ><div><p><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>AAGE Events</p></div></div><div ><div><p>Develop your professional skills and enhance your graduate program by attending our events and conference.</p></div></div><div ><div><a href="/page.html?slug=upcoming-events" target="_blank" rel="noopener">Upcoming Events</a></div></div></div></div></td></tr></table></div></div></div></div>', false, false, NULL, true);
INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('about', 'About', '<div><div><div><div><table><tr><td><div><div><div ><div><h1>The peak body for graduate recruitment and development</h1></div></div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><br></p></div></div></div></div></td></tr></table></div></div></div></div><!-- /content zone --><!-- footer zone --><div><div><div><div><table><tr><td><div><div><div ><div><p>Welcome to the Australian Association for Graduate Employers</p></div></div><div ><div><p>The peak industry body for graduate recruitment and development <br></p></div></div><div ><div><p>The AAGE is the peak industry body for the graduate recruitment and development market in Australia. We support organisations that recruit and develop graduates or which offer services in connection with graduate recruitment and development. Our current membership comprises over 450 employers, including a variety of large and small organisations across a wide range of industries in both the private and public sectors. We also offer Associate Membership for service providers, industry associations and universities.</p><p><span><span>The AAGE is the only representative body in the Australian graduate recruitment market that is run by employers for employers.&nbsp;</span></span><span>We are led by a board and committee of volunteer members who help coordinate our member offering. This structure gives the AAGE a unique ability to provide our members with valuable and relevant services.</span></p></div></div><div ><div><p>Becoming a member of the AAGE will help you and your organisation</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p>Relationships</p></div></div><div ><div><p>Build strong relationships with graduate employers, industry associations, service providers and universities.</p></div></div><div ><div><p><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>Insights</p></div></div><div ><div><p>Make better informed decisions thanks to access to exclusive insights, research and market intelligence produced for AAGE members.</p></div></div><div ><div><br></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>Expertise</p></div></div><div ><div><p>Celebrate excellence<strong>,</strong> be recognised for your expertise and implement best practice adopted by leaders in early careers.</p></div></div><div ><div><br></div></div></div></div></td></tr></table></div><div ><div><p>Governance</p></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/member-group-3-373-987d2523-6c804178.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><span>The AAGE''s Governance processes are determined by our Constitution and policies:</span><br><ul><li><span><a href="https://pr-9q32ba.run402.com/_blob/assets/aage/2023-aage-constitution-988a87b6-2c36886a.pdf" target="_blank" rel="noopener">AAGE Constitution</a></span></li><li><a href="https://pr-9q32ba.run402.com/_blob/assets/aage/accc-australian-consumer-law-refund-policy-6f2aeb2f-b7a3600e.pdf" target="_blank" rel="noopener">ACCC Australian Consumer Law Refund Policy</a></li><li><a href="https://pr-9q32ba.run402.com/_blob/assets/aage/aage-code-of-conduct-final-230524-dec6a13b-66545992.pdf" target="_blank" target="_blank" rel="noopener">Code of Conduct</a></li><li><a href="https://pr-9q32ba.run402.com/_blob/assets/aage/aage-committee-charter-final-30122021-05647f48-cae967e1.pdf" target="_blank" rel="noopener">Committee Charter</a></li><li><a href="https://pr-9q32ba.run402.com/_blob/assets/aage/aage-complaint-management-procedure-f3e07c23-989fd24c.pdf" target="_blank" target="_blank" rel="noopener">Complaint Management Procedure</a></li><li><a href="https://pr-9q32ba.run402.com/_blob/assets/aage/aage-conflict-of-interest-policy-2025-6397f387-c46d122b.pdf" target="_blank" target="_blank" rel="noopener">Conflict of Interest Policy</a></li><li><a href="https://pr-9q32ba.run402.com/_blob/assets/aage/aage-director-appointments-policy-june-2023-final-bd17aa6d-17302527.pdf" target="_blank" rel="noopener">Director Appointments Policy</a></li><li><a href="https://pr-9q32ba.run402.com/_blob/assets/aage/aage-directors-charter-agreement-august-2018-3a029afe-3964999b.pdf" target="_blank" rel="noopener">Director''s Charter</a>&nbsp;</li><li><a href="https://pr-9q32ba.run402.com/_blob/assets/aage/sponsorship-endorsements-and-gifts-policy-e36f1acf-7cf547a8.pdf" target="_blank" target="_blank" rel="noopener">Sponsorships, Partnerships, Endorsements and Gifts Policy</a></li><li><a href="https://pr-9q32ba.run402.com/_blob/assets/aage/aage-marketing-media-communications-policy-2025-333dd1a2-6a58e8bb.pdf" target="_blank" target="_blank" rel="noopener">Marketing, Media and Communications Policy</a></li><li><a href="https://pr-9q32ba.run402.com/_blob/assets/aage/privacy-policy-statement-2025-ca784843-91b26ff5.pdf" target="_blank" target="_blank" rel="noopener">Privacy Policy</a></li><li><a href="https://pr-9q32ba.run402.com/_blob/assets/aage/aage-whistleblower-policy-final-31052024-a06612e8-dcf1a1a8.pdf" target="_blank" rel="noopener">Whistleblower Policy</a></li></ul><br></div></div></div></div></td></tr></table></div></div></div></div>', false, false, NULL, true);
INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('board', 'AAGE Board', '<div><div><div><div><table><tr><td><div><div><div ><div><h1>Run by employers for employers</h1></div></div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td><td><div></div></td><td></td></tr></table></div></div></div></div><!-- /content zone --><!-- footer zone --><div><div><div><div><table><tr><td><div><div><div ><div><p>AAGE Board<br></p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/5-0b84d989-a79f1688.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>Joanne Dean - Chair and Elected Director</p></div></div><div ><div><p><strong>Senior Manager, Early Careers, Ashurst<br>B. Education</strong></p><p></p><p>Jo is the Senior Manager, Early Careers at Ashurst and has over 15 years'' experience in Early Careers across Legal and Retail industries. Her expertise includes attraction, selection and development of early careers talent. Strengths include leadership, stakeholder management, strategy and project management.</p><p><strong>Appointments</strong></p><ul><li><span>AAGE Board:&nbsp;August 2023</span></li><li><span>Committee Appointment: AAGE Nominations Committee</span></li></ul></div></div></div></div></td></tr></table></div><div ><div></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/7-f367b1a1-aa38b979.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>Ann Brinkamp - Elected Director<br></p></div></div><div ><div><p><strong>Manager - Early Careers, Monadelphous Group<br> BCom (DHBW Stuttgart)</strong></p><p>Ann has 20 year experience across Talent Acquisition and Talent Development across private, not-for-profit and member-based organisations, both in Europe and Australia. Her background in Early Talent Development ranges from Program Strategy and Design, through to end-to-end execution and review, targeted a variety of Early Talent Cohorts including VET and tertiary education pathways.</p><p><strong>Appointments</strong></p><ul><li><p>AAGE Board: August 2023</p></li><li>Committee Appointment: Co-Chair, Associate Member Advisory Group</li></ul></div></div></div></div></td></tr></table></div><div ><div><p><br></p></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/4-5711421f-b1ee0ca6.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>Kelly Pfeffer - Elected Director</p></div></div><div ><div><p><strong>Graduate Talent Lead, Suncorp</strong></p><p>Kelly is the Graduate Talent Lead at Suncorp for Australia and New Zealand with 15+ years experience in the early careers industry across both private and public sector organisations. Prior to this, Kelly specialised in HR Policy and Legislation, Recruitment, and Learning and Development roles.</p><p>Kelly has been an AAGE member since 2006 and previously volunteered on the Committee and Board from 2011 to 2019.</p><p><strong>Appointments</strong><br></p><ul><li>AAGE Board: May 2014 - October 2019, October 2023</li><li>Committee Appointment: Co-Chair, AAGE Committee</li></ul></div></div></div></div></td></tr></table></div><div ><div></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/darcy-richardson-7e2db872-a8d965be.png" alt="" title="" loading="lazy"><img src="https://aage.com.au/resources/Pictures/Asmaa%20Zahid.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><h3>Darcy Richardson</h3></div></div><div ><div><p><strong>Talent Partner, Urban Utilities</strong></p><p>Based in Brisbane, Darcy is currently the Talent Partner at Urban Utilities, where he oversees the delivery and management of early careers programs. His leadership has supported the development of graduates and interns across the industry, ensuring robust and supportive pathways for emerging talent. He also served on the AAGE Committee during 2025 and 2026.</p><p>Darcy holds an undergraduate degree and in 2026, he is studying Career Development and Counselling to broaden his expertise in supporting early careers professionals. He is passionate about fostering resilient, inclusive, and diverse workforces, and actively champions opportunities for all individuals to thrive within their chosen fields.</p><p><strong>Appointments</strong></p><ul><li>AAGE Board: April 2026</li></ul></div></div></div></div></td></tr></table></div><div ><div><p><br></p></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/madeleine-west-4189715e-2f2815bd.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>Maddie West - Elected Director</p></div></div><div ><div><p><strong>Senior Early Careers Specialist, Arup<br>B. Business (Applied International Business)<br></strong></p><p>Passionate about advancing diversity and inclusion, Maddie has dedicated the last 5 years to making a meaningful impact in early careers. With a background in both the banking and engineering consulting industries, Maddie has recruited graduates and interns across Australia, New Zealand, Singapore, Indonesia, and Malaysia.</p><p>In addition to her early careers experience, Maddie works independently as a disability support worker. In this role, she supports clients in accessing social support and offering domestic assistance.</p><p>Maddie''s creative mindset is a driving force behind her ability to challenge conventional limitations and think outside the box. As a proud member of Generation Z herself, Maddie uses this creative mindset to craft innovative strategies that resonate effectively with the target demographic.</p><p><strong>Appointments</strong><br></p><ul><li>AAGE Board: October 2024</li></ul></div></div></div></div></td></tr></table></div><div ><div></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/6-a13e94ef-27dd4cc0.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>Fulvio Barbuio - Co-Opted Director</p></div></div><div ><div><p><strong>BCom Hon, FCTA (Australian Corporate Treasury Association), FCPA (CPA Australia), MAICD (Australian Institute of Company Directors)</strong><br></p><p>In a corporate career spanning over 40 years, Fulvio has gained a broad and deep level of experience in senior management and professional roles in finance, treasury, strategy, planning, financial and business analysis, enterprise risk management and insurance. A focus on excellence and high performance has been at the centre of his career ethos.</p><p>From 2014 he also transitioned into Non-Executive Director roles and apart from his role at AAGE, he was previously a Non-Executive Director of Business Excellence Australia and a Non-Executive Director and Vice President at the Australian Corporate Treasury Association. These roles have added a governance and whole of business lens to his corporate experiences, equipping him to make a strong contribution to organisational success.</p><p><strong>Appointments</strong><br></p><ul><li>AAGE Board: November 2021</li><li> Committee Appointments: AAGE Finance, Audit &amp; Risk Committee, AAGE Nominations Committee</li></ul></div></div></div></div></td></tr></table></div><div ><div></div></div><div><table><tr><td><div><div><div ><div><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/8-f5a24607-5cf3bd5d.png" alt="" title="" loading="lazy"></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>Amita Laroiya - Co-Opted Director</p></div></div><div ><div><p><strong>General Manager, Group Corporate Governance and Company Secretary, Auto &amp; General</strong></p><p><strong>LLB/Justice Studies (QUT), Grad Dip Legal Practice (College of Laws), Grad Dip Applied Corporate Governance (GIA), GAICD (Australian Institute of Company Directors)</strong></p><p>Amita is the General Manager, Group Corporate Governance and Company Secretary at Auto &amp; General and possesses over 20 years of professional experience specialising in corporate governance, corporate and commercial law in both private practice and in-house roles across the financial services sector.</p><p>Her expertise ranges from providing advice on matters of corporate governance, risk management, and delivery of high level legal and commercial advice for her clients.</p><p><strong>Appointments</strong><br></p><ul><li>AAGE Board: December 2021</li><li>Committee Appointments: Chair, AAGE Finance, Audit &amp; Risk Committee</li></ul></div></div></div></div></td></tr></table></div><div ><div></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/rachal-morice-a49f7b31-c6077308.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>Rachal Morice - Company Secretary</p></div></div><div ><div><p><strong>B Business (Accounting), Graduate Certificate in Human Resources, MAICD (Australian Institute of Company Directors), AGIA (Governance Institute of Australia)</strong></p><p>Rachal supports the Board&#8217;s effectiveness by providing governance advice, overseeing statutory and regulatory obligations, and ensuring strong governance practices across the organisation. She works closely with the Board and CEO to enable clear decision making, transparency and accountability in support of AAGE&#8217;s purpose and strategic direction.</p><p>Rachal is passionate about good governance as an enabler of trust and strong organisational outcomes.</p><p><strong>Appointments</strong><br></p><p></p><ul><li>AAGE Board: February 2026</li></ul></div></div></div></div></td></tr></table></div><div ><div></div></div></div></div></div>', false, false, NULL, true);
INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('committee', 'AAGE Committee', '<div><div><div><div><table><tr><td><div><div><div ><div><h1>Run by employers for employers</h1></div></div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td><td><div></div></td><td></td></tr></table></div></div></div></div><!-- /content zone --><!-- footer zone --><div><div><div><div><table><tr><td><div><div><div ><div><p>AAGE Committee</p></div></div><div ><div><p><span>The AAGE Committee is made up of a number of experienced employer members who regularly meet to form the ''engine room'' of the AAGE. Representing a cross-section of the broader membership, our dedicated committee members volunteer their experience, wisdom and expertise year on year to ensure the growth and success of the AAGE. You can find more information on joining the AAGE Committee below.</span><br></p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/claire-battafarano-c63bf424-a8117702.png" alt="" title="" loading="lazy"><p><img src="https://aage.com.au/resources/Pictures/Claire%Battafarano.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>Claire Battafarano</p></div></div><div ><div><p><strong>Graduate Program Lead and Learning Ambassador, Boeing Defence Australia</strong></p><p>Claire Battafarano is the Graduate Program Lead at Boeing Defence Australia. She began her professional career in media planning and communication strategy in New York City, working on campaigns for major brands like The Home Depot, Dannon and Pepsi. Her passion for talent development led her to transition into human resources, starting with an HR Business Partner internship at Boeing in Seattle. This experience paved the way for a full-time role in the HR Career Foundation Program in St. Louis, where she gained a breadth of knowledge in HR.</p><p>After completing the program, Claire took on the role of Strategy and Integration Lead for Entry Level Development Programs, collaborating with global teams to launch two US-based development programs. In 2022, she moved to Brisbane to lead Boeing Defence Australia&#8217;s Graduate Program. Claire holds an MBA in HR Management from Michigan State University and a B.S. in Advertising from the University of Texas at Austin, along with certification as an HR Professional through the Society of HR Management. Her unique blend of advertising and HR expertise enhances her approach to talent development.</p></div></div></div></div></td></tr></table></div><div ><div></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/charlie-cowell-bffbdc5f-1de2c6c6.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>Charlie Cowell</p></div></div><div ><div><p><strong>Graduate Program Manager, Commonwealth Bank</strong></p><p>Charlie is the Graduate Program Manager at Commonwealth Bank, leading development programs for graduates and interns across data science, quantitative and predictive modelling, AI and machine learning. He supports recruitment, structured onboarding, rotation design and performance development, ensuring early careers talent contribute to high impact analytical and technical work while building capability through bootcamps and learning experiences.</p><p>Before joining CommBank, Charlie managed emerging careers programs at BDO in Australia, delivering vacation and graduate recruitment, campus engagement and assessment processes across Queensland. He has also held early careers roles with Chartered Accountants Australia and New Zealand and began his career in professional services recruitment with Hays. A two-time AAGE Top Graduate Recruiter nominee, he is committed to creating meaningful pathways for emerging talent and supporting future focused workforce capability.</p></div></div></div></div></td></tr></table></div><div ><div></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/lynaire-eccles-c8797ff8-3a3d7d0d.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><h3>Lynaire Eccles</h3></div></div><div ><div><p><strong>Senior Talent Acquisition Business Partner &#8211; Early Careers, BDO</strong></p><p>Lynaire is a dedicated Early Careers specialist and currently works as a Senior Talent Acquisition Business Partner &#8211; Early Careers at BDO in Australia. In her role, she leads student attraction and recruitment, delivers BDO&#8217;s vacationer and graduate programs, engages with high schools and leads key national projects, including the design and implementation of BDO&#8217;s graduate program and the firm&#8217;s high school outreach initiatives. She is also an active member of BDO&#8217;s Women@BDO committee, contributing to initiatives that support gender equity and an inclusive workplace.</p><p>With over seven years&#8217; early careers experience across Australia, New Zealand and the United Kingdom, within professional services, construction and technology, Lynaire brings strong expertise in student recruitment and emerging talent development. Her work is driven by a strong commitment to shaping high-quality candidate experiences and building inclusive programs that empower emerging talent to thrive.</p></div></div></div></div></td></tr></table></div><div ><div></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/rasika-grice-60b08145-86eaca62.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>Rasika Grice</p></div></div><div ><div><p><strong>Entry Level Programs Team Leader, Services Australia</strong></p><p>Rasika currently leads a team in supporting the delivery of robust and innovative Entry Level Programs within Services Australia, with a portfolio focus on graduate program learning and development, pastoral care and the Cadet program from end to end. Rasika is especially passionate about leadership development and capability uplift within early careers and the broader workforce.</p><p>She has had a variety of HR experience through Policy, Advisory and Business Partnering within her early tenure, whilst always finding her way back to Entry Level Programs. Having been a HR graduate after completing her Bachelor of Psychological Science (First Class Honours) at the University of Queensland, she has experienced firsthand the impact graduate programs and early careers have on participants and the everchanging workforce. Rasika is eager to continue investing in entry level participants, ensuring they are valued and empowered to adapt, innovate and discover their passions in the workplace.</p></div></div></div></div></td></tr></table></div><div ><div></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/lauren-howard-fc578745-932eecc9.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><h3>Lauren Howard</h3></div></div><div ><div><p><strong>Senior Consultant &#8211; Early Careers, Australian Energy Market Operator</strong></p><p>Lauren works at the Australian Energy Market Operator (AEMO), where she leads the design and delivery of an industry-wide rotational Grid Connection Engineering Graduate Program. Working in close partnership with leading organisations across the sector, she helps build critical capability to support Australia&#8217;s energy transition. Now in its second year, Lauren is proud to have brought this program to life and to continue pushing the boundaries of a traditional graduate program.</p><p>With experience across graduate recruitment, employer branding and recruitment technology, Lauren has held leadership roles spanning program design, recruitment marketing and stakeholder engagement across the financial services, higher education and energy sectors. She is particularly passionate about innovative, collaborative approaches that improve outcomes for employers, graduates and the broader industry.</p></div></div></div></div></td></tr></table></div><div ><div><p><br></p></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/kate-minns-0b91a221-4396a1ff.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><h3>Kate Minns</h3></div></div><div ><div><p><strong>National Talent Acquisition Lead, Grant Thornton</strong></p><p>Kate is the National Talent Acquisition Leader at Grant Thornton Australia, overseeing the design and development of Grant Thornton&#8217;s national early talent recruitment strategy and employer branding, as well as managing the day-to-day operations of the broader talent acquisition team. With over 12 years&#8217; experience in the Professional Services sector and 10 years in the graduate recruitment and talent acquisition space, Kate has a passion for helping students navigate their options for graduate employment and helping organisations to identify exceptional talent and potential.</p><p>She holds a Bachelor of Laws and Bachelor of Accounting from QUT in Brisbane.</p></div></div></div></div></td></tr></table></div><div ><div></div></div><div><table><tr><td><div><div><div ><div><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/suhar-osman-a6d31859-e7bf8733.png" alt="" title="" loading="lazy"><p><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><h3>Suhar Osman</h3></div></div><div ><div><p><strong>Talent and Inclusive Program Consultant, Department of Energy, Environment, and Climate Action (VIC)</strong></p><p>Suhar works in the Victorian Public Service she brings over seven years of experience in organisational development, specialising in diversity and inclusion, learning and development, and employment programs. She began her career at the Department of Treasury and Finance, where she supported the implementation and delivery of the department&#8217;s first Diversity Scholarship Program.</p><p>Passionate about driving organisational success through people, Suhar has a strong focus on fostering diversity within teams and creating inclusive pathways for emerging talent. Currently, Suhar serves as the Talent and Inclusive Program Consultant at the Department of Energy, Environment, and Climate Action, overseeing the end-to-end delivery of the department&#8217;s Science Graduate Program and working across internships and work experience initiatives.</p></div></div></div></div></td></tr></table></div><div ><div></div></div><div><table><tr><td><div><div><div ><div><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/james-schlunke-4a1d929f-9d53dce7.png" alt="" title="" loading="lazy"><p><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>James Schlunke</p></div></div><div ><div><p><strong>Head of Early Careers, Capgemini</strong></p><p>James is an award-winning early careers professional with a strong background in project management, business analysis and functional consulting. He is an empathy-driven leader and digital inclusion champion who is passionate about developing others and forming meaningful connections with graduates, external partners and all other stakeholders.</p><p>James has accumulated a track record of excellent results and has helped drive Capgemini''s early careers team to several accolades and industry recognitions, including the number one-rated graduate program for graduate satisfaction (AAGE) in 2023 and 2024, the number one-rated graduate program for graduate satisfaction and brand popularity (Prosple) in 2024 and 2025, and being recognised as the most popular graduate program for technology consulting (Financial Review/GradConnection) in 2023, 2024 and 2025. In 2025, Capgemini was named Most Popular Overall Graduate Employer (Financial Review/GradConnection and won the AAGE Graduate Recruitment Industry Award for Outstanding Graduate Program (Graduate Intake Over 50).</p></div></div></div></div></td></tr></table></div><div ><div></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/greta-treloar-9d1583b6-ac1c7225.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><h3>Greta Treloar<br></h3></div></div><div ><div><p><strong>Early Careers, Lendlease</strong></p><p>Greta&#8217;s passion for Early Careers began at university, where she completed an internship designing graduate assessment centres. Since then, Greta has developed an expertise in attracting and retaining emerging talent across diverse industries. Greta started her career in Canberra in Big Four consulting before relocating to Sydney and transitioning into the legal sector. Today, Greta manages Early Careers in the construction industry at Lendlease. Greta is passionate about employer branding and designing early identification initiatives that connect high-potential students with meaningful career opportunities.</p></div></div></div></div></td></tr></table></div><div ><div></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/sam-turnpenny-e622b858-774a08d5.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><h3>Sam Turnpenny<br></h3></div></div><div ><div><p><strong>Early Careers Manager, Clayton Utz</strong></p><p>Sam is an early careers specialist with experience designing and delivering early talent strategies across the UK, US, EMEA and Australia. He has led entry-level recruiting and early careers programs for global organisations spanning law, tech, finance and consulting, and has built student development and employability programs for universities and non-profits. Sam is passionate about social mobility and supporting young people from underrepresented backgrounds into graduate employment. He also has a keen interest in HR technology and has conducted academic research on AI adoption in talent acquisition. Sam holds a master''s degree in global human resource management and is a certified member of the Australian HR Institute and the CIPD.</p></div></div></div></div></td></tr></table></div><div ><div></div></div><div ><div><p>Interested in joining the AAGE Committee?</p></div></div><div ><div><p>The expectations of a committee member are as follows:</p><ul><li>Attend monthly AAGE Committee meetings via teleconference (approximately one hour per month).</li><li>Bring fresh, creative ideas to the table and provide input on all issues raised by the Committee.</li><li>Advocate the AAGE and support recruiting new members. Attend local events and host events from time to time (e.g. providing venue, presenting or MC-ing).</li><li>Be involved on a sub-committee or a major project during the year.</li><li>Be prepared and available to be interviewed from time to time for various media.</li><li>Attend AAGE Annual Conference and provide input, such as hosting workshop sessions or presenting.</li><li>Work towards further developing the AAGE and its mission to improve graduate outcomes through networking.</li></ul><p>Nominations for the 2025 AAGE Committee have now closed. Please contact us if you would like to express your interest in joining the Committee should a position become available.&nbsp;</p></div></div><div ><div><a href="mailto:info@aage.com.au" target="_blank" rel="noopener">Contact us</a></div></div><div ><div><p><br></p></div></div></div></div></div>', false, false, NULL, true);
INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('team', 'AAGE Team', '<div><div><div><div><table><tr><td><div><div><div ><div><h1>Run by employers for employers</h1></div></div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td><td><div></div></td><td></td></tr></table></div></div></div></div><!-- /content zone --><!-- footer zone --><div><div><div><div><table><tr><td><div><div><div ><div><p>AAGE Team<br></p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/shanan-headshots-290-907f3bf2-4e015136.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>Shanan Green <br></p></div></div><div ><div><p><span><strong>Chief Executive Officer</strong></span></p><p><span>Shanan''s involvement with the AAGE began in 2005 when she first joined the AAGE Committee, before becoming an AAGE Director in 2006.&nbsp; Shanan spent eight years with Macquarie Bank where her most recent appointment was as the Head of Recruitment. During her career at Macquarie, Shanan also lead the Graduate Recruitment Team for three years, worked in IT recruitment and was responsible for the MBA Scholarship Program.&nbsp;</span><span>She returned to the AAGE in 2008 where her responsibilities include managing the research for the AAGE&#8217;s annual surveys and planning some of the AAGE&#8217;s annual events including the Conference.</span><span>&nbsp;Shanan was appointed Acting Chief Executive Officer of the AAGE in 2022 and Chief Executive Officer in 2023.&nbsp;</span><span>She has an honours degree in Economics (Social Science) from the University of Sydney.</span></p></div></div></div></div></td></tr></table></div><div ><div></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/leoni-davis-9966b3df-c0aa9805.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>Leoni Davis</p></div></div><div ><div><p><strong>Memberships and Marketing Manager</strong></p><p>Leoni joined the AAGE in May 2014 as Memberships and Marketing Manager. Leoni has a broad marketing background including experience in event, program, project and relationship management. Her previous role was as the Events and Sponsorship Manager for Melbourne Business School where she led the Events department. Prior to this, she held several different roles within KPMG''s marketing team and also has experience in the FMCG industry. Leoni graduated from the University of Melbourne <br></p></div></div></div></div></td></tr></table></div><div ><div></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/samantha-duff-7b326a01-bb741f94.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>Samantha Duff</p></div></div><div ><div><p><strong>Partnerships and Events Manager</strong></p><p>Sam joined the AAGE in June 2008 in the role of Events Manager and then moved to our Marketing and Memberships Manager role. Prior to joining the AAGE, Sam worked for Peter Rowland Catering and Epicure Catering managing a range of both private and corporate events, as well as large scale events such as the Australian Grand Prix and Spring Racing Carnival. Sam also worked in the hospitality industry for many years whilst completing her Bachelor of Business including owning and running her own licensed café and catering business. She left the AAGE in 2013 to pursue family business interests and we welcomed her back into the role of Events Manager in October 2018.</p></div></div></div></div></td></tr></table></div><div ><div></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/olivia-johnson-99f606f4-69437e72.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>Olivia Johnson<br></p></div></div><div ><div><p><strong>Events Manager</strong></p><p>Olivia joined the AAGE in August 2010 to assist with the ever-expanding role of AAGE Events Coordinator. Prior to commencing, Olivia worked for Destination Event Management where she was an Account Manager involved with the coordination of large scale events, product launches, conferences &amp; expos, as well as incentive travel. Olivia has also had experience working in the hospitality industry for many years, during which time she also completed a Bachelor of Business in Hospitality &amp; Event Management. <br></p></div></div></div></div></td></tr></table></div><div ><div></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/georgia-nery-5ec0590e-97d51a2a.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>Georgia Nery</p></div></div><div ><div><p><strong>Member Services and Events Coordinator</strong></p><p>Georgia holds a background in marketing, events and social media. Her previous experience includes working within the membership team at the Australian Psychological Society (APS), Pitcher Partners and most recently as Marketing Manager and Business Developer for her family business, Get Ya Yum On. She is passionate about creating impactful experiences and events, and fostering meaningful connections within the membership community.</p></div></div></div></div></td></tr></table></div><div ><div></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/samantha-skinner-00bc765f-3e27c0ef.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>Samantha Skinner</p></div></div><div ><div><p><strong>Insights and Engagement Project Manager</strong></p><p>With a background in career education and workforce development, Samantha brings experience as a consultant and from her work in the NSW Department of Education, at UNSW Sydney and with NSW Minerals Council. Samantha is a firm believer in the power of data and partnerships to support meaningful outcomes for people at the earliest stages of their career journey.<br></p></div></div></div></div></td></tr></table></div><div ><div></div></div><div><table><tr><td></td></tr></table></div></div></div></div>', false, false, NULL, true);
INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('media', 'Media and Announcements', '<div><div><div><div><table><tr><td><div><div><div ><div><h1>Latest news from the peak body for graduate recruitment and development&nbsp;</h1></div></div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td><td><div></div></td><td></td></tr></table></div></div></div></div><!-- /content zone --><!-- footer zone --><div><div><div><div><table><tr><td><div><div><div ><div><p>Media and Announcements</p></div></div><div ><div><p><span>The Australian Association of Graduate Employers (AAGE) is the peak industry body for the Australian graduate recruitment and development market.</span></p><p><span>Contact AAGE Chief Executive Officer, Shanan Green, for media interviews and insights on the sector.&nbsp;</span></p></div></div><div ><div><a href="mailto:shanan@aage.com.au" target="_blank" rel="noopener">Contact Shanan</a><p><br></p></div></div><div ><div ><div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><span><span>&lt;&lt; First</span></span><span><span>&nbsp;&lt; Prev&nbsp;</span></span><span>&nbsp;1&nbsp;</span><a href="/page.html?slug=media" target="_blank" rel="noopener">&nbsp;2&nbsp;</a><a href="/page.html?slug=media" title="Next page" target="_blank" rel="noopener">&nbsp;Next &gt;&nbsp;</a><a href="/page.html?slug=media" title="Last page" target="_blank" rel="noopener">Last &gt;&gt;&nbsp;</a><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><ul><li><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><h4><a href="/page.html?slug=media-13601006" target="_blank" rel="noopener">Australian Association of Graduate Employers launches 2026 Top Graduate Employers lists</a></h4><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><h5><span>23 Feb 2026 1:00 PM</span> | <span><a href="/page.html?slug=sys-publicprofile-24411688" target="_blank" rel="noopener">Anonymous member</a><span> (Administrator)</span></span></h5></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><p>The Australian Association of Graduate Employers (AAGE), the peak industry body for the early careers market, is pleased to announce the publication of the 2026 Top Graduate Employers lists. Now in their thirteenth year, the Top Graduate Employers rankings are the definitive guide to the best places to work for new graduates entering the workforce.</p><p>The Top Graduate Employers listed are the organisations that provided the most positive experiences for new graduates based on the opinions of graduates themselves. The rankings are determined entirely from survey feedback gathered from over 3,200 graduates who are in their first year of employment at over 180 organisations across Australia. The AAGE commissioned McCrindle to administer the survey which was conducted between November and December 2025.</p><p>The survey is completed anonymously and graduates are asked to rate their employer on 31 different categories including:</p><ul><li>Orientation or induction program</li><li>Training and development program</li><li>Quality of work</li><li>Career progression</li><li>Support and guidance from supervisor, manager and HR</li><li>Access to mentoring and networking</li><li>Compensation and benefits</li><li>Work/life balance</li><li>Wellbeing support</li><li>The opportunity for community involvement</li><li>Company culture.</li></ul><p>This analysis of responses from graduates in relation to these categories provides a comprehensive measurement of each employer''s performance across a broad range of criteria.</p><p>All of the individual responses from graduates at a particular employer are combined and used to determine an overall average rating for that organisation. These overall average ratings are then compared and ranked, subject to a minimum response rate. Employers have been ranked in one of three lists of 25 based on their intake size, enabling improved comparability and usability. A total of 75 employers are featured across these three lists. The employers with the highest overall average rating are shown on the Start My Career website at <a href="http://www.startmycareer.com.au/Top-Graduate-Employers" target="_blank" target="_blank" rel="noopener">www.startmycareer.com.au/Top-Graduate-Employers</a>.</p><p>For further information, please contact Shanan Green, Chief Executive Officer, Australian Association of Graduate Employers at <a href="mailto:shanan@aage.com.au" target="_blank" target="_blank" rel="noopener">shanan@aage.com.au</a>.</p></div><a name="addComment" target="_blank" rel="noopener"></a><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div messageId="13601006"><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><a href="/page.html?slug=media-13601006" target="_blank" rel="noopener">Read more</a><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div></div><div></div><div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div></li><li><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><h4><a href="/page.html?slug=media-13564892" target="_blank" rel="noopener">Press Release: AAGE Chair Appointment</a></h4><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><h5><span>20 Nov 2025 11:00 AM</span> | <span><a href="/page.html?slug=sys-publicprofile-24411688" target="_blank" rel="noopener">Anonymous member</a><span> (Administrator)</span></span></h5></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><p>Following the recent Annual General Meeting, the Board of Directors of the Australian Association of Graduate Employers (AAGE) would like to issue an update on changes to the Board.</p><p><strong>Robert Blaze</strong>, who has served as the Chair of the AAGE Board from October 2023 and a Director since 2019, has reached the end of his term. During this time, Rob has lead the AAGE through a period of significant growth and development. The Board thanks Rob for his service to the Board, the AAGE and the early careers industry.</p><p>The Board has voted <strong>Joanne Dean</strong>, who has served on the Board since 2023, as the new Chair of the AAGE Board of Directors.</p><p>Jo is the Senior Manager, Early Careers at Ashurst and has over 15 years'' experience in Early Careers across Legal and Retail industries. Her expertise includes attraction, selection and development of early careers talent. Strengths include leadership, stakeholder management, strategy and project management.</p><p>“I am honoured to be appointed Chair of the Board of Directors and extend my sincere thanks to Rob for his outstanding leadership and dedication. I am genuinely excited about the organisation’s direction. I am fully committed to supporting the AAGE team, Board and Committee in advancing our strategic priorities and to building on the excellent work already underway.”</p><p><em>Joanne Dean, Chair and Elected Director, AAGE</em></p><p>The Board would like to thank Rob for his service to the AAGE and congratulate Jo on her appointment.</p><p>Please contact <a href="mailto:info@aage.com.au" target="_blank" target="_blank" rel="noopener">info@aage.com.au</a> for further information.</p></div><a name="addComment" target="_blank" rel="noopener"></a><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div messageId="13564892"><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><a href="/page.html?slug=media-13564892" target="_blank" rel="noopener">Read more</a><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div></div><div></div><div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div></li><li><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><h4><a href="/page.html?slug=media-13501525" target="_blank" rel="noopener">Press Release: Australian Association of Graduate Employers launches new student platform startmycareer.com.au and the 2025 Top Intern Programs lists</a></h4><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><h5><span>21 May 2025 3:30 PM</span> | <span><a href="/page.html?slug=sys-publicprofile-24411688" target="_blank" rel="noopener">Anonymous member</a><span> (Administrator)</span></span></h5></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><p>The Australian Association of Graduate Employers (AAGE), the peak body for the early careers industry, is pleased to announce the publication of the 2025 Top Intern Programs lists on the new platform <strong><a href="https://startmycareer.com.au/" target="_blank" target="_blank" rel="noopener">startmycareer.com.au</a></strong>. This site brings together all AAGE student-facing initiatives to make it easier than ever for students to explore career paths and what our members have to offer.</p><p>The first component of this site to launch is the Top Intern Programs rankings. Now in their twelfth year, the rankings serve as the authoritative guide for those seeking employers that provide exceptional internship experiences, helping them make well-informed decisions about their career opportunities.</p><p>The organisations listed as a Top Intern Program are those that offered the most positive experiences for interns, based solely on intern feedback. The rankings are derived entirely from responses collected in the annual AAGE Intern Survey, which gathered responses from July 2024 to February 2025. More than 2,500 interns from 127 different organisations participated, providing valuable insights into their internship experiences.</p><p>The AAGE commissioned McCrindle to administer the survey where students anonymously rated their internship employer across 15 different criteria including:</p><ul><li>Induction and training</li><li>Content of work</li><li>Ability to work on different projects or in different areas of the organisation</li><li>Quality of supervision provided by management</li><li>Amount of responsibility</li><li>Access to senior management</li><li>Feedback on performance</li><li>Social life</li><li>Organisation''s culture and values.</li></ul><p>The subsequent analysis provides a comprehensive assessment of each employer''s performance across the broad range of criteria. The individual responses from interns at a particular employer are combined and used to determine an overall average rating for that organisation. The overall average ratings are then compared and ranked, subject to a minimum response rate. The Top Intern Programs have been ranked in one of three lists of 20 based on their intake size, enabling improved comparability and usability. A total of 60 employers are featured across these three lists. The employers with the highest overall average rating are shown at <strong><a href="https://startmycareer.com.au/Top-Intern-Programs" target="_blank" target="_blank" rel="noopener">startmycareer.com.au/Top-Intern-Programs</a></strong>. For further information please contact Shanan Green, Chief Executive Officer, Australian Association of Graduate Employers, <a href="mailto:shanan@aage.com.au" target="_blank" target="_blank" rel="noopener">shanan@aage.com.au</a>.</p><p><br></p></div><a name="addComment" target="_blank" rel="noopener"></a><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div messageId="13501525"><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><a href="/page.html?slug=media-13501525" target="_blank" rel="noopener">Read more</a><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div></div><div></div><div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div></li><li><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><h4><a href="/page.html?slug=media-13464839" target="_blank" rel="noopener">Press Release: Australian Association of Graduate Employers launches 2025 Top Graduate Employers lists</a></h4><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><h5><span>19 Feb 2025 12:30 PM</span> | <span><a href="/page.html?slug=sys-publicprofile-24411688" target="_blank" rel="noopener">Anonymous member</a><span> (Administrator)</span></span></h5></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><p>The Australian Association of Graduate Employers (AAGE), the peak industry body for the graduate recruitment and development market, is pleased to announce the publication of the 2025 Top Graduate Employers lists. Now in its thirteenth year, the Top Graduate Employers rankings are the definitive guide to the best places to work for new graduates entering the workforce.</p><p>The Top Graduate Employers listed are the organisations that provided the most positive experiences for new graduates based on the opinions of graduates themselves. The rankings are determined entirely from survey feedback gathered from over 4,100 graduates who are in their first year of employment at over 220 organisations across Australia. The AAGE commissioned McCrindle to administer the survey which was conducted between November and December 2024.</p><p>The survey is completed anonymously and graduates are asked to rate their employer on around 30 different categories including:</p><ul><li>Orientation or induction program</li><li>Training and development program</li><li>Quality of work</li><li>Career progression</li><li>Supervisor or manager</li><li>Compensation and benefits</li><li>Work/life balance</li><li>Company culture</li></ul><p>This analysis of responses from graduates in relation to these categories provides a comprehensive measurement of each employer''s performance across a broad range of criteria.</p><p>All of the individual responses from graduates at a particular employer are combined and used to determine an overall average rating for that organisation. These overall average ratings are then compared and ranked, subject to a minimum response rate. Employers have been ranked in one of three lists of 25 based on their intake size, enabling improved comparability and usability. A total of 75 employers are featured across these three lists. The employers with the highest overall average rating are shown at <a href="http://www.topgraduateemployers.com/" target="_blank" target="_blank" rel="noopener">www.topgraduateemployers.com</a>.</p><p>For further information please contact Shanan Green, Chief Executive Officer, Australian Association of Graduate Employers, <a href="mailto:shanan@aage.com.au" target="_blank" target="_blank" rel="noopener">shanan@aage.com.au</a>.</p></div><a name="addComment" target="_blank" rel="noopener"></a><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div messageId="13464839"><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><a href="/page.html?slug=media-13464839" target="_blank" rel="noopener">Read more</a><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div></div><div></div><div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div></li><li><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><h4><a href="/page.html?slug=media-13434526" target="_blank" rel="noopener">Press Release: AAGE Director Appointment - Madeline West</a></h4><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><h5><span>25 Nov 2024 10:00 AM</span> | <span><a href="/page.html?slug=sys-publicprofile-24411688" target="_blank" rel="noopener">Anonymous member</a><span> (Administrator)</span></span></h5></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><p>Following the recent Annual General Meeting (AGM), the Board of Directors of the Australian Association of Graduate Employers (AAGE) would like to update the AAGE membership on changes to the Board. These include the departure of <strong>Thomasin Schmidt</strong> who has stepped down at the end of her Director term and the appointment of <strong>Madeline West</strong> as Director.</p><p>Thomasin Schmidt has served on the AAGE Committee since 2015 and the Board since November 2018 including serving as Chair from October 2020 – 2023. During her time on the Board, Thomasin led the development of the new strategy, contributed to the review and implementation of policies and processes, and supported the AAGE through a period of significant change. The Board thanks Thomasin for her service to the Board, the AAGE and the early careers industry.</p><p>With Thomasin’s departure, Madeline West was appointed as a Director during the 2024 AGM. The Board is thrilled to welcome Madeline onto the Board given her passion for the industry and experience she brings. Madeline is located in Brisbane where she is the Senior Early Careers Specialist at Arup, having dedicated the last five years to making a meaningful impact in early careers. With a background in both the banking and engineering consulting industries, Madeline has recruited graduates and interns across Australia, New Zealand, Singapore, Indonesia and Malaysia. In addition to her early careers experience, Madeline works independently as a disability support worker. In this role, she supports clients in accessing social support and offering domestic assistance. The Board is looking forward to the contribution that Madeline will make as a Director of the AAGE.</p><p>With this appointment, the AAGE Board will be:</p><ul><li>Robert Blaze, Member Director and Chair</li><li>Ann Brinkamp, Member Director</li><li>Joanne Dean, Member Director</li><li>Kelly Pfeffer, Member Director</li><li>Madeline West, Member Director</li><li>Fulvio Barbuio, Co-opted Director</li><li>Amita Laroiya, Co-opted Director</li><li>Allyson Yule, Company Secretary</li></ul><p>Please contact <a href="mailto:info@aage.com.au" target="_blank" target="_blank" rel="noopener">info@aage.com.au</a> for further information.</p></div><a name="addComment" target="_blank" rel="noopener"></a><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div messageId="13434526"><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><a href="/page.html?slug=media-13434526" target="_blank" rel="noopener">Read more</a><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div></div><div></div><div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div></li><li><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><h4><a href="/page.html?slug=media-13401092" target="_blank" rel="noopener">Press Release: AAGE launches 2024 Top Intern Programs lists</a></h4><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><h5><span>14 May 2024 9:00 AM</span> | <span>Deleted user</span></h5></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><p>The Australian Association of Graduate Employers (AAGE), the peak industry body for the early careers market, is pleased to announce the publication of the 2024 Top Intern Programs lists.</p><p>For the eleventh year in a row, the Top Intern Program rankings provide an authoritative guide for identifying employers that offer outstanding internship experiences, helping students to make informed decisions about their career opportunities.</p><p>The Top Intern Programs have been ranked in one of three lists of 20 based on their intake size, enabling improved comparability and usability. A total of 60 employers are featured across these three lists. The rankings are based entirely on feedback from interns themselves sourced from the annual AAGE Intern Survey. The AAGE commissioned McCrindle to administer the 2024 AAGE Intern Survey.</p><p>The survey was in the field between January and March 2024, surveying respondents who were engaged by a participating employer during the March 2023 – February 2024 period. Over 2,400 interns from 147 different organisations participated, offering valuable insights into the internship experience.</p><p>The survey is completed anonymously and students are asked to rate their employer across 15 different criteria including:</p><ul><li>Induction and training</li><li>Content of work</li><li>Ability to work on different projects or in different areas of the organisation</li><li>Quality of supervision provided by management</li><li>Amount of responsibility</li><li>Access to senior management</li><li>Feedback on performance</li><li>Social life</li><li>Organisation''s culture and values</li></ul><p>The subsequent analysis provides a comprehensive assessment of each employer''s performance across the broad range of criteria. The individual responses from interns at a particular employer are combined and used to determine an overall average rating for that organisation. The overall average ratings are then compared and ranked, subject to a minimum response rate. The employers with the highest overall average rating are shown at www.topinternprograms.com.au.</p><p>For further information please contact <a href="/page.html?slug=page-18252" target="_blank" target="_blank" rel="noopener">Shanan Green</a>, AAGE CEO.</p></div><a name="addComment" target="_blank" rel="noopener"></a><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div messageId="13401092"><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><a href="/page.html?slug=media-13401092" target="_blank" rel="noopener">Read more</a><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div></div><div></div><div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div></li><li><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><h4><a href="/page.html?slug=media-13401094" target="_blank" rel="noopener">Press Release: AAGE launches 2024 Top Graduate Employers lists</a></h4><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><h5><span>14 Feb 2024 9:00 AM</span> | <span>Deleted user</span></h5></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><p>The Australian Association of Graduate Employers (AAGE), the peak industry body for the graduate recruitment and development market, is pleased to announce the publication of the 2024 Top Graduate Employers lists.</p><p>Now in its twelfth year, the Top Graduate Employers rankings are the definitive guide to the best places to work for new graduates entering the workforce. The Top Graduate Employers listed are the organisations that provided the most positive experiences for new graduates based on the opinions of graduates themselves.</p><p>The rankings are determined entirely from survey feedback gathered from over 4,000 graduates who are in their first year of employment with these organisations. The AAGE commissioned McCrindle to administer the survey which was conducted between November and December 2023.</p><p>The survey participants are all current graduates who joined their employer''s graduate program sometime in 2023, so they have up to 12 months of experience with their organisation.</p><p>The survey is completed anonymously and graduates are asked to rate their employer on around 30 different categories including:</p><ul><li>Orientation or induction program</li><li>Training and development program</li><li>Quality of work • Career progression</li><li>Supervisor or manager</li><li>Compensation and benefits</li><li>Work/life balance</li><li>Company culture</li></ul><p>This analysis of responses from graduates in relation to these categories provides a comprehensive measurement of each employer''s performance across a broad range of criteria.</p><p>All of the individual responses from graduates at a particular employer are combined and used to determine an overall average rating for that organisation. These overall average ratings are then compared and ranked, subject to minimum response rate.</p><p>This year, employers have been ranked in one of three lists of 25 based on their intake size, enabling improved comparability and usability. A total of 75 employers are featured across these three lists. The employers with the highest overall average rating are shown at ww.topgraduateemployers.com.</p><p>For further information please contact Shanan Green, Chief Executive Officer, Australian Association of Graduate Employers.</p></div><a name="addComment" target="_blank" rel="noopener"></a><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div messageId="13401094"><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><a href="/page.html?slug=media-13401094" target="_blank" rel="noopener">Read more</a><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div></div><div></div><div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div></li><li><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><h4><a href="/page.html?slug=media-13419487" target="_blank" rel="noopener">Press Release: AAGE Director Appointments and Transition of Chair</a></h4><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><h5><span>01 Nov 2023 4:19 PM</span> | <span>Deleted user</span></h5></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><p>Following the recent Annual General Meeting, the Board of Directors of the Australian Association of Graduate Employers (AAGE) would like to update the AAGE membership on changes to the Board.</p><p>These include the departure of Chery Koe who has stepped down at the end of her Director term, the appointment of Kelly Pfeffer as Director and the transition of the Chair role to Robert Blaze.</p><p>Cheryl Koe has served on the AAGE Board since November 2020, during which time Cheryl has contributed to the development of the new strategy and supporting the AAGE through a period of significant change.</p><p>The Board thanks Cheryl for her service to the Board, the AAGE and the industry. With Cheryl’s departure, Kelly Pfeffer was appointed as a Director during 2023 AGM. The Board is thrilled to welcome Kelly onto the Board given the depth of both industry and governance experience she brings.</p><p>In addition to this Director appointment, Thomasin Schmidt who has served as the Chair of the AAGE Board from October 2020 has reached the end of her term as Chair so the Board has voted Robert Blaze as the new Chair of the AAGE Board of Directors.</p><p>“I am both honoured and privileged to have been able to serve as Chair of the AAGE for the past three years and am proud of what the Board and the AAGE team has achieved together over this time. The Board is delighted to appoint Robert Blaze to the role of Chair and is confident that we will continue to progress on our strategic journey under his leadership” said Ms Schmidt, ex-Chair of the AAGE Board.</p><p>Incoming Chair of the Board Mr Blaze said, “I am delighted to have been appointed to Chair of the Board of Directors and thank Thomasin for her unwavering leadership and devotion in leading the AAGE Board in a time of unprecedented change and strategic focus.</p><p>The AAGE has been a huge part of my professional life for several years and I am extremely excited at the direction the organisation is heading. I am fully committed to assisting the AAGE team, Board and Committee in driving the organisation’s strategic direction and will continue the amazing work that that has already commenced in this space.”</p><p>Kelly Pfeffer Graduate Talent Lead, Suncorp Kelly is located in Brisbane and is the Graduate Talent Lead at Suncorp, specialising in early careers talent programs for 15+ years in both private and public sector organisations. This includes working in industries such as Finance, Insurance, Technology, Engineering and Consulting with programs operating across Australia, New Zealand, USA and Canada. Prior to this, Kelly worked in a number of human resource related roles including policy, performance management, diversity and learning and development. Kelly has been an AAGE member since 2006 and has previously volunteered on the Committee and Board from 2011 to 2019.</p><p>With these appointments, the AAGE Board will be:</p><ul><li>• Rob Blaze, Member Director and Chair</li><li>• Ann Brinkamp, Member Director</li><li>• Joanne Dean, Member Director 2.</li><li>• Kelly Pfeffer, Member Director</li><li>• Thomasin Schmidt, Member Director</li><li>• Fulvio Barbuio, Co-opted Director</li><li>• Amita Laroiya, Co-opted Director.</li></ul><p>Please contact info@aage.com.au for further information</p></div><a name="addComment" target="_blank" rel="noopener"></a><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div messageId="13419487"><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><a href="/page.html?slug=media-13419487" target="_blank" rel="noopener">Read more</a><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div></div><div></div><div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div></li><li><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><h4><a href="/page.html?slug=media-13419964" target="_blank" rel="noopener">Press Release: AAGE Director Appointments</a></h4><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><h5><span>22 Aug 2023 12:05 PM</span> | <span>Deleted user</span></h5></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><p>Following the recent Expression of Interest process, the Board of Directors of the Australian Association of Graduate Employers (AAGE) is excited to announce the appointment of two new Directors – Ann Brinkamp and Joanne Dean – who will join the Board with immediate effect.</p><p>“We’re thrilled to welcome Ann and Jo to the AAGE Board,” said Ms Schmidt, Chair of the AAGE Board. “Both of them have deep experience in the early careers sector across a range of different sectors and geographies. Their addition to the Board will further enhance and balance the skills on the Board as we continue to focus on our strategic direction as the peak industry body for the early careers sector in Australia”.</p><p><strong>Ann Brinkamp</strong></p><p>Ann is Manager - Early Careers for Monadelphous Group in Perth, where she leads the national vacation, graduate and apprentice development programs. Ann has extensive experience in the design and delivery of full-lifecycle talent development programs, as well as initiatives building employability and work-readiness skills. With involvement in the talent acquisition and development sector dating back to 2002, initially in Germany and then Australia, Ann brings a wealth of experience across not-for-profit and private organisations in multiple industries. Ann has been a member representative of the AAGE on behalf of multiple companies and also has prior governance experience of membership organisations having sat on the Board for Triathlon Western Australia.</p><p><strong>Joanne Dean</strong></p><p>Jo is currently Senior Manager Early Careers based in Sydney for global law firm, Ashurst. She is responsible for leading and coordinating the national graduate program in Australia with a focus on consistency, efficiency, and quality. Jo is passionate about attracting top talent and assisting students transition from university to a career in law. Over the past 13 years Jo has specialised in graduate recruitment and development, both in her current role and prior to Ashurst for a major retailer. Jo also has experience in generalist HR, management of recognition programs and facilitation of talent development programs. Jo has been a member representative of the AAGE on behalf of a number of organisations and for the last two years, she has further contributed to our industry through her involvement with the AAGE Committee.&nbsp;</p><p>With these appointments, the AAGE Board will be:</p><ul><li>Thomasin Schmidt, Member Director and Chair</li><li>Rob Blaze, Member Director</li><li>Cheryl Koe, Member Director</li><li>Ann Brinkamp, Member Director</li><li>Joanne Dean, Member Director</li><li>Fulvio Barbuio, Co-opted Director</li><li>Amita Laroiya, Co-opted Director.</li></ul><p>Please contact info@aage.com.au for further information.</p></div><a name="addComment" target="_blank" rel="noopener"></a><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div messageId="13419964"><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><a href="/page.html?slug=media-13419964" target="_blank" rel="noopener">Read more</a><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div></div><div></div><div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div></li><li><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><h4><a href="/page.html?slug=media-13419979" target="_blank" rel="noopener">Statement from the AAGE Board</a></h4><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><h5><span>22 Jun 2023 12:25 PM</span> | <span>Deleted user</span></h5></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div><p>In September 2022, our previous CEO Benjamin Reeves resigned from his role at the Australian Association of Graduate Employers (AAGE).</p><p>Mr Reeves was dealing with legal proceedings relating to personal matters that are not in any way connected to his role or employment at the AAGE.</p><p>The AAGE continues to focus on delivering excellent outcomes for its members.</p><p>Please direct any queries to Thomasin Schmidt, AAGE Chair of the Board, at c<a href="mailto:hair@aage.com.au" target="_blank" target="_blank" rel="noopener">hair@aage.com.au</a>.</p></div><a name="addComment" target="_blank" rel="noopener"></a><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div messageId="13419979"><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><a href="/page.html?slug=media-13419979" target="_blank" rel="noopener">Read more</a><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div></div><div></div><div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div></li></ul><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div><div><div><div></div><div></div><div></div><div></div><div></div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--></div></div><div ><div><div><div><div><div><div><div><div><div><div><span><span>&lt;&lt; First</span></span><span><span>&nbsp;&lt; Prev&nbsp;</span></span><span>&nbsp;1&nbsp;</span><a href="/page.html?slug=media" target="_blank" rel="noopener">&nbsp;2&nbsp;</a><a href="/page.html?slug=media" title="Next page" target="_blank" rel="noopener">&nbsp;Next &gt;&nbsp;</a><a href="/page.html?slug=media" title="Last page" target="_blank" rel="noopener">Last &gt;&gt;&nbsp;</a><div></div></div></div></div></div></div></div></div></div></div></div></div><div><div><!--[if gt IE 6]><!--><div><div><div><div><div></div></div></div></div></div><!--<![endif]--><div></div><div></div><div></div><div></div><div></div></div></div></div><div></div></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><br></p></div></div></div></div></td></tr></table></div></div></div></div>', false, false, NULL, true);
INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('contact-us', 'Contact Us', '<div><div><div><div><table><tr><td><div><div><div ><div><h1>Get in touch</h1></div></div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td><td><div></div></td><td></td></tr></table></div></div></div></div><!-- /content zone --><!-- footer zone --><div><div><div><div><table><tr><td><div><div><div ><div> Feedback, queries or suggestions?</div></div><div ><div> Contact the AAGE Team</div></div><div ><div><a href="mailto:info@aage.com.au" target="_blank" rel="noopener">Email</a></div></div><div ><div><p>AAGE<br>Camberwell PS<br> PO Box 1217<br> Camberwell VIC 3124<br> Australia&nbsp;</p><p>Tel:&nbsp;<a href="tel:+61-3-9352-5062" target="_blank" rel="noopener">+61 3 9352 5062</a></p><div> &nbsp;<a href="mailto:info@aage.com.au" target="_blank" rel="noopener">info@aage.com.au</a></div></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-e9feb2ad-06d988aa.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td></tr></table></div></div></div></div>', false, false, NULL, true);
INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('join-us', 'Join Us', '<div><div><div><div><table><tr><td><div><div><div ><div><h1>Join our supportive community</h1></div></div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td></tr></table></div></div></div></div><!-- /content zone --><!-- footer zone --><div><div><div><div ><div><p>Become an AAGE member today!</p></div></div><div><table><tr><td><div><div><div ><div><p>More than 1,400 graduate recruitment and development professionals representing 600+ organisations are part of the AAGE community. Becoming a member of the AAGE will help you and your organisation to:&nbsp;</p><ul><li>Build <strong>relationships</strong> with graduate employers, industry associations, suppliers and universities</li><li>Make informed decisions with access to exclusive <strong>insights</strong>, information and market intelligence</li><li>Celebrate excellence<strong>,</strong> be recognised for your <strong>expertise</strong> and implement best practice adopted by the leaders and innovators in graduate recruitment and development.</li></ul></div></div><div ><div><p><a href="/page.html?slug=member-benefits" target="_blank" rel="noopener">Member Benefits</a><br></p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p>Discover the right membership for your organisation</p></div></div><div ><div><p>AAGE offers two main types of membership, Full or Associate. Membership is corporate (in other words, AAGE memberships are sponsored and retained by the organisation). Each organisation nominates a primary Member Representative to represent their organisation''s view on graduate recruitment and development. These nominated Member Representatives are then eligible to receive membership benefits. Additional representatives from the same organisation are also able to join for a nominal fee, so your whole team can benefit from everything that the AAGE offers.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p>Full Membership</p></div></div><div ><div><div><p>Full membership is for employer organisations committed to best practice in graduate recruitment and development.</p></div></div></div><div ><div><a href="/page.html?slug=join" target="_blank" rel="noopener">Join now</a></div></div><div ><div><p><strong>Full Membership</strong> is an annual membership for <strong>employer organisations</strong>&nbsp;and includes one primary representative. </p><p>Additional representatives can be added to the membership, so your whole team can benefit from everything that the AAGE offers.</p><p><strong>Fees</strong> ($AUD ex. GST)</p><ul><li>Primary Full Membership: $450 per year</li><li>Additional Full Membership: $110 per person per year.</li></ul></div></div><div ><div><p>"The AAGE has been instrumental in helping us stay up to date with the latest industry trends and best practices. Their events and forums have provided invaluable networking opportunities and insights, further strengthening our recruitment strategies."</p></div></div><div ><div><p><strong>Silvana Naumovski<br>CSL</strong></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>Associate Membership&nbsp;</p></div></div><div ><div><div><p>Associate membership is for industry associations,&nbsp;service providers to the early careers sector&nbsp;and universities.</p></div></div></div><div ><div><a href="/page.html?slug=join" target="_blank" rel="noopener">Join now</a></div></div><div ><div><p>The AAGE offers three types of <strong>Associate Membership</strong><span>, depending on your organisation type</span>:</p><p><strong>Associate Membership</strong></p><p>This option is available to <strong>service providers</strong> to the early careers industry.</p><p><strong>Fees</strong> ($AUD ex. GST)</p><ul><li><span>Primary Associate Membership: $550 per year</span></li><li><span>Additional Associate Membership: $150 per person per year.</span></li></ul><p><strong>Associate (Not-For-Profit) Membership</strong></p><p>This option is available to <strong>industry associations</strong> and <strong>universities</strong>.</p><p><span><strong></strong></span></p><p><strong>Fees</strong> ($AUD ex. GST)</p><ul><li><span>Primary Associate (Not-for-Profit) Membership: $250 per year</span></li><li><span>Additional <span>Associate (Not-for-Profit) Membership:</span>&nbsp;$90 per person per year.</span></li></ul><p>Full Careers Service Membership</p><p>Universities may also take out a&nbsp;<strong>Full Careers Service Membership</strong>&nbsp;which enables an entire Careers department to access member benefits.</p><p><strong></strong></p><p><strong>Fees</strong> ($AUD ex. GST)</p><ul><li><span>Associate Membership (Full Careers Service): $350 per year.</span></li></ul></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p>Constitution</p></div></div><div ><div><p>All members must comply with the <a href="https://pr-9q32ba.run402.com/_blob/assets/aage/2023-aage-constitution-988a87b6-2c36886a.pdf" target="_blank" target="_blank" rel="noopener">AAGE Constitution</a> and any other rules and regulations applicable to members.</p><p>In accordance with the Corporations Act and AAGE Constitution, as AAGE is a company limited by guarantee, in the event that AAGE is dissolved or wound up and its assets are not sufficient to discharge its liabilities, you must contribute, and your liability as a member is limited to contributing up to $100.</p></div></div></div></div></td></tr></table></div></div></div></div>', false, false, NULL, true);
INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('why-join', 'Why Join?', '<div><div><div><div><table><tr><td><div><div><div ><div><h1>Relationships. Insight. Expertise.</h1></div></div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td></tr></table></div></div></div></div><!-- /content zone --><!-- footer zone --><div><div><div><div ><div><p>Build Strong Relationships</p></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/conference-290-c0ca4c62-cc61a2ca.png" alt="" title="" loading="lazy"><br></p></div></div><div ><div><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/workshop-290-f1c113f8-94fddb21.png" alt="" title="" loading="lazy"></div></div><div ><div><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/the-big-meet-290-2aaa987e-1e552cad.png" alt="" title="" loading="lazy"></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>AAGE Annual Conference</p></div></div><div ><div><p><span>The annual&nbsp;</span><a href="/page.html?slug=conference" target="_blank" rel="noopener">AAGE Conference</a><span>&nbsp;focuses on the professional development of our members and addresses key graduate recruitment and development topics such as the ''how to of graduate recruitment'', the latest industry innovations and the big issues facing the early careers industry today.&nbsp;</span><span>Member representatives are entitled to substantially discounted delegate rates, saving up to $400 + GST on conference registration fees.</span></p></div></div><div ><div><p>Roundtables, Webinars and Videoconferences</p></div></div><div ><div><a href="/page.html?slug=events" target="_blank" rel="noopener">AAGE member events</a><span>&nbsp;such as Roundtables, Webinars and Videoconferences are held throughout year and are complimentary for members. Non-members can attend these events for a fee where applicable. &nbsp;Chosen themes are a direct response to current industry trends and issues, but regardless of theme or format, the focus remains on knowledge sharing and networking. Regular feedback from members highlights the invaluable opportunity of expanding one''s network and sharing experiences with others in the early careers industry.</span></div></div><div ><div><p>The Big Meet</p></div></div><div ><div><p><a href="/page.html?slug=the-big-meet" target="_blank" rel="noopener">The Big Meet</a><span>&nbsp;is a one-day careers fair which is promoted to all students from all universities in each host city. Currently, The Big Meet events are hosted in Adelaide, Brisbane, Perth, Melbourne and Sydney in March/April each year.&nbsp;</span></p><p><span>The Big Meet careers fairs were created as a result of feedback received from employers from both the private and public sector.&nbsp;</span><span>Employers have asked for an effective and efficient way to promote themselves to potential candidates rather than attending several different careers fairs in the same city. AAGE members can access significant exhibitor discounts ($400 + GST per space per event).</span></p></div></div><div ><div><p>AAGE Mentor Program</p></div></div><div ><div><p><span>AAGE employer members have the opportunity to participate in our free AAGE Mentor Program.&nbsp;</span><span>The Mentor Program is designed to help connect and support new AAGE employer members by matching them with experienced employers within the AAGE membership body.</span></p><p><span>The program is completely voluntary and is a great way to connect with other industry professionals.</span><br></p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p>Gain Exclusive Insights</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p>Annual AAGE Candidate Survey</p></div></div><div ><div><p><a href="/page.html?slug=candidate-survey" target="_blank" rel="noopener">The Candidate Survey</a> is designed to survey all the candidates who have been offered a graduate position with an AAGE Full Member organisation each year. The survey collects data on a range of topics including factors which influence application and offer acceptance decisions, experience through the recruitment and selection process, the use of artificial intelligence in recruitment and selection processes, and discernment around offer acceptance and the reasons why candidates renege. Any AAGE Full Member who participates receives a FREE detailed Insights Report summarising the feedback collected. Non-members can purchase this report and non-participating members can access the report at a discounted price. </p></div></div><div ><div><p>Annual AAGE Employer Survey</p></div></div><div ><div><a href="/page.html?slug=employer-survey" target="_blank" rel="noopener">The Employer Survey</a><span>&nbsp;is designed to survey AAGE employer members, providing ways for employers to benchmark themselves against their competitors and help them to plan for upcoming graduate campaigns.&nbsp;The survey collects data on a range of topics including early careers program strategy and inclusions, how to find the right talent and which approaches are effective, campaign statistics including vacancy levels, application numbers and progress data, remuneration and benefits provided, and how employers are developing early careers talent.&nbsp;Any AAGE Full Member who participates receives a FREE detailed Insights Report summarising the feedback collected. Non-members can purchase this report and non-participating members can access the report at a discounted price.</span></div></div><div ><div><p>Annual AAGE Graduate Survey</p></div></div><div ><div><p><a href="/page.html?slug=graduate-survey" target="_blank" rel="noopener">The Graduate Survey</a> is designed to collect data from graduates who have recently completed 12 months of full time employment on a graduate program. The survey collects perspectives and experiences on a range of graduate program aspects including onboarding, professional development, on-the-job experiences and broader organisational engagement.. Any AAGE Full Member who participates receives a FREE detailed Insights Report summarising the feedback collected. Non-members can purchase this report and non-participating members can access the report at a discounted price. </p></div></div><div ><div><p>Annual AAGE Intern Survey</p></div></div><div ><div><p><a href="/page.html?slug=intern-survey" target="_blank" rel="noopener">The Intern Survey</a> is designed to collect data from students who have participated in work experience placement programs. The survey collects data from these interns on a range of attitudes and opinions towards their employer and about their experiences on their internship program. Any AAGE Full Member who participates receives a FREE detailed Insights Report summarising the feedback collected. Non-members can purchase this report and non-participating members can access the report at a discounted price. </p></div></div><div ><div><p>AAGE UniStats Report</p></div></div><div ><div><p>The <a href="/page.html?slug=reports-guides" target="_blank" rel="noopener">UniStats Report</a> provides detailed statistics on the number of students who commence and complete an undergraduate degree at Australian universities. The original data is collected by the Australian Government and the AAGE packages this information into a number of charts and tables. This data is broken down by university and degree subject, giving AAGE members the ability to identify the number and location of candidates with specific qualifications. The AAGE UniStats Report is provided free of charge to all AAGE members via the <a href="/page.html?slug=member-zone" target="_blank" target="_blank" rel="noopener">Member Zone</a>.</p></div></div><div ><div><p>AAGE UniGrades Report</p></div></div><div ><div><p>The AAGE UniGrades Report provides a summary of the exam grading structure for all Australian universities. For each university there is a description of the grades used (e.g. Higher Distinction, Distinction, Credit etc) as well as the percentage band allocated to each grade. The AAGE UniGrades Report is provided free of charge to all AAGE Members via the <a href="/page.html?slug=member-zone" target="_blank" rel="noopener">Member Zone</a>. </p></div></div><div ><div><p>AAGE SocList</p></div></div><div ><div><p>The AAGE''s SocList document provides a summary of the contact details for over 700 different student societies at universities across Australia. SocList is useful for employers that are targeting particular degree subjects that wish to make contact with the relevant student body. SocList is provided free of charge to all AAGE Members via the <a href="/page.html?slug=member-zone" target="_blank" rel="noopener">Member Zone</a>. </p></div></div><div ><div><p>Member Zone</p></div></div><div ><div><p>The AAGE website hosts a <a href="/page.html?slug=member-zone" target="_blank" rel="noopener">Member Zone</a>, containing member-only information and conveniently available to each member once logged into their profile. </p></div></div><div ><div><p>Member eNewsletter</p></div></div><div ><div><p>We keep members up to speed with industry ''happenings'' as well as AAGE news and events through our quarterly electronic newsletter. <br></p></div></div><div ><div><p>Industry Job Vacancies</p></div></div><div ><div><p>The AAGE posts industry jobs on our website at no cost to AAGE members. This service provides members with a method of advertising available positions in the graduate recruitment and development space to one another.&nbsp;Visit the <a href="/page.html?slug=jobs" target="_blank" rel="noopener">Industry Job Vacancies</a>&nbsp;for further information. </p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/conference-290-c0ca4c62-cc61a2ca.png" alt="" title="" loading="lazy"></div></div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/employer-d723fbe5-58db9ba2.png" alt="" title="" loading="lazy"><br></p></div></div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/graduate-af02fdd9-4fdcfe12.png" alt="" title="" loading="lazy"><br></p></div></div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/intern-50449ee3-0b45d59a.png" alt="" title="" loading="lazy"><br></p></div></div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/candidate-74214119-86635fa2.png" alt="" title="" loading="lazy"><br></p></div></div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/member-zone-d9e7109e-d63c95b6.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p>Celebrate Excellence and Expertise</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><br></p><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/agria-full-no-border-1bd828a3-06f2a293.png" alt="" title="" loading="lazy"><br></p></div></div><div ><div><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/top-graduate-logo-no-year-373-7b90e0cb-51bc1d48.png" alt="" title="" loading="lazy"></div></div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/top-intern-programs-no-yeaar-373-0810b5ec-61b53c5d.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>Annual AAGE Graduate Recruitment Industry Awards (AGRIAs)<br></p></div></div><div ><div><p>Each year the AAGE rewards outstanding examples of excellence in the graduate recruitment industry through its annual <a href="/page.html?slug=agrias" target="_blank" rel="noopener">AAGE Graduate Recruitment Industry Awards (AGRIAs)</a>. The AGRIAs are a wonderful opportunity to showcase your organisation as an industry leader and we encourage ALL members to enter the Awards and gain solid recognition for their winning strategies. Winners are announced at the AAGE annual Gala Dinner, which takes place during the annual Graduate Recruitment Conference.</p></div></div><div ><div><p>Top Graduate Employers Lists</p></div></div><div ><div><p>The aim of the <a href="/page.html?slug=top-graduate-employers" target="_blank" rel="noopener">Top Graduate Employers</a> lists is to recognise those organisations which provide the most positive experience for their new graduates as determined by the graduates themselves.</p><p>​The Top Graduate Employers lists are created from the results of the AAGE''s annual Graduate Survey. The survey participants are all current graduates who have up to 12 months of full-time experience with their organisation.</p><p>All the individual responses from graduates at a particular employer are combined and used to determine an overall average rating for that organisation. This same process is followed for each separate employer to produce an overall average rating for each organisation based on the responses of its own graduates.&nbsp;</p></div></div><div ><div><p>Top Interns Program Lists</p></div></div><div ><div><p>The aim of the <a href="/page.html?slug=top-intern-programs" target="_blank" rel="noopener">Top Intern Programs</a> lists is to recognise those organisations which provide the most positive experience for their interns as determined by the interns themselves.</p><p>The Top Intern Programs lists are created from the results of the AAGE''s annual Intern Survey. The survey participants are all current undergraduates who were part of their employer''s intern program.​ Therefore, respondents have first hand knowledge of the employer''s intern program.</p><p>All the individual responses from interns at a particular employer are combined and used to determine an overall average rating for that organisation. This same process is followed for each separate employer to produce an overall average rating for each organisation based on the responses of its own interns.&nbsp;</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><br></p></div></div></div></div></td></tr></table></div></div></div></div>', false, false, NULL, true);
