INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('employer-members', 'Employer Members', '<div><div><div><div><table><tr><td><div><div><div ><div><h1>Join leading employers as members of the AAGE</h1></div></div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td><td><div></div></td><td><div><div><div ><div></div></div></div></div></td></tr></table></div></div></div></div><!-- /content zone --><!-- footer zone --><div><div><div><div><table><tr><td><div><div><div ><div><p>Employer Members</p></div></div><div ><div><p>Around 450 graduate employers in Australia are members of AAGE, including a variety of large and small organisations across a wide range of industries in both the private and public sectors. Don''t see your company below? We''d love to welcome you as a member.</p></div></div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/home-page-big-meet-8eaeb4ce-207c9a66.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><strong>#</strong></p><p>5 Sticks Consulting</p><p><strong>A</strong></p><p>Ability Action Australia/MedHealth</p><p>Accenture Australia</p><p>ACCIONA</p><p>Accru Melbourne</p><p>ACT Government</p><p>Adecco Australia<br> ADF Careers</p><p>AECOM Australia</p><p>Airwallex</p><p>Alcoa - Australia</p><p>Alinta Energy</p><p>Allens</p><p>Allianz Australia</p><p>Alstom<br> Altus Financial</p><p>AMP</p><p>Ampol</p><p>ANCA</p><p>AngloGold Ashanti</p><p>ANZ Banking Group (Aust)</p><p>APA Group</p><p>Arcadis</p><p>Argon &amp; Co</p><p>Arup</p><p>ASC<br> Ashfords</p><p>Ashurst</p><p>Atlassian</p><p>Attorney-General''s Department</p><p>Audit Office of South Australia<br> Atturra</p><p>Aurecon Au