man<br></p><p>Pitcher Partners Advisors</p><p>PKF Melbourne<br>Plan Group<br>Plena Healthcare<br> PLS</p><p>Powercor</p><p>Powerlink Queensland</p><p>Procter &amp; Gamble<br>Protiviti</p><p>Prysmian</p><p>Public Sector Commission (Qld)</p><p>Public Sector Commission (WA)</p><p>Public Transport Authority</p><p>PwC</p><p><br></p><p><strong>Q</strong></p><p><br></p><p>Qantas</p><p>QBE Australia &amp; New Zealand</p><p> QIC</p><p>Quantium</p><p>Queensland Audit Office</p><p>Queensland Government Digital Graduate Program<br>Queensland Police Service</p><p>Queensland Rail</p><p>Queensland Treasury</p><p><br></p><p><strong>R</strong></p><p><br></p><p>RAA</p><p>Rabobank</p><p>Ramsay Health Care</p><p>Raytheon Australia</p><p>REA Group</p><p>REDARC Electronics</p><p>Reece Group</p><p>Reserve Bank of Australia</p><p>ResMed</p><p>Rheinmetall Defence Australia</p><p>Rio Tinto<br>RMIT University</p><p>Robson Environmental<br>Rohde &amp; Schwarz<br>Rokt</p><p>RSM Australia<br>Rystad Energy</p><p><br></p><p><strong>S</strong></p><p><br></p><p>SA Health</p><p>SA Power Networks</p><p>SA Water</p><p>Saab Australia</p><p>SAGE Automation</p><p>SAHMRI</p><p>Salesforce</p><p>Santos</p><p>SAP Australia</p><p>Schneider Electric Australia<br> Scyne<br>Seed Ability</p><p>SEEK</p><p>Services Australia</p><p>Shoal</p><p>Siemens</p><p>Siemens Healthineers</p><p>SIG</p><p>SingTel Optus</p><p>SLB</p><p>SMEC Australia</p><p>South Australian Tourism Commission</p><p>Spiire</p><p>Stanmore Resources</p><p>Stantec</p><p>Stanwell</p><p>Stockland</p><p>Suburban Rail Loop Authority</p><p>Suncorp</p><p>Sungrow Australia Group<br></p><p>SunPork Group</p><p>SW Accountants &amp; Advisory</p><p>Sydney Water</p><p>Symal Group</p><p>Symbio</p><p>Synergy</p><p>SYSTRA Scott Lister</p><p><br></p><p><strong>T</strong></p><p><br></p><p>TAL</p><p>TasNetworks</p><p>Teach For Australia<br>TechnologyOne</p><p>Telstra Corporation</p><p>Thales Australia</p><p>The Alternative</p><p>The NDIS Commission</p><p>The Salvation Army</p><p>Thermo Fisher Scientific</p><p>Thiess</p><p>Thoughtworks Australia</p><p>Tourism Australia</p><p>Transgrid</p><p>Transport for NSW</p><p>Turner &amp; Townsend</p><p><br></p><p><strong>U</strong></p><p><br></p><p>UNIQLO Australia<br>Unitywater</p><p>Urban Utilities</p><p>Urbis</p><p><br></p><p><strong>V</strong></p><p><br></p><p>V/Line Corporation</p><p>Ventia<br>VicRoads</p><p>Victoria Legal Aid</p><p>Victorian Auditor-General''s Office</p><p>Victorian Government Graduate Program</p><p>Victorian Infrastructure Delivery Authority</p><p>Viva Energy</p><p>VivCourt</p><p>VMware<br>Volkswagen Financial Services Australia</p><p><br></p><p><strong>W</strong></p><p><br></p><p>Water Corporation</p><p>Wesfarmers Chemicals, Energy &amp; Fertilisers</p><p>Western Power</p><p>Westpac Group</p><p>WEX</p><p>WGA</p><p>White &amp; Case</p><p>Whitehaven Coal</p><p>William Buck<br>Windcave</p><p>Wood</p><p>Woodside Energy</p><p>Worley</p><p>WSP Australia Pty</p><p><br></p><p><strong>X</strong></p><p><br></p><p>Xero</p><p><br></p><p><strong>Y</strong></p><p><br></p><p>Yarra Valley Water</p><p><br></p></div></div></div></div></td></tr></table></div></div></div></div>', false, false, NULL, true);
INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('industry-association-members', 'Industry Association Members', '<div><div><div><div><table><tr><td><div><div><div ><div><h1>Join leading service providers as members of the AAGE</h1></div></div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td><td><div></div></td><td><div><div><div ><div></div></div></div></div></td></tr></table></div></div></div></div><!-- /content zone --><!-- footer zone --><div><div><div><div ><div><p>Industry Association Members</p></div></div><div ><div> Professional associations with an allied interest in advancing the graduate recruitment and development industry can join the AAGE and work collaboratively with us in our role as the peak industry body to promote the interests of the early careers sector. Want to get involved?</div></div><div><table><tr><td><div><div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td><td><div></div></td><td></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-anziif-8610b9bf-b26d6721.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><span><a href="https://anziif.com/" target="_blank" target="_blank" rel="noopener">ANZIIF</a>&nbsp;| <a href="mailto:customerservice@anziif.com" target="_blank" target="_blank" rel="noopener">customerservice@anziif.com</a> |&nbsp;03 9613 7200</span></p><p>ANZIIF is the leading membership, training and professional development organisation for the insurance and finance industry in the Asia-Pacific region. We partner with a broad range of organisations and government to provide services that support professional excellence. We help enhance standards and improve community understanding of insurance and finance.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-acs-b7c1d519-dcc158bb.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><span><a href="https://www.acs.org.au/" target="_blank" target="_blank" rel="noopener">Australian Computer Society (ACS)</a>&nbsp;| <a href="mailto:member.services@acs.org.au" target="_blank" target="_blank" rel="noopener">member.services@acs.org.au</a> | 02 9299 3666</span></p><p>ACS (Australian Computer Society) is Australia''s leading professional association with over 40,000 members, strengthening Australia''s technology community and digital skills capabilities through career pathways, professional development, and skills assessment services. We create the talent pipeline that ensures Australia has employment-ready technology professionals with the right skills and knowledge for the evolving tech landscape.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-acs-foundation-72b628d9-f680b8ab.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><span><a href="http://www.acsfoundation.com.au/" target="_blank" target="_blank" rel="noopener">Australian Computer Society Foundation</a>&nbsp;|&nbsp;<a href="mailto:info@acsfoundation.com.au" target="_blank" target="_blank" rel="noopener">info@acsfoundation.com.au</a> | 02 8296 7744</span></p><p>The ACS Foundation is dedicated to advancing Australia''s technology sector through education and research. The ACS Foundation was founded by the Australian Computer Society in 2001 and runs developmental programs for students that align with the strategic goals of Australia''s technology sector. We engage with governments, industry groups, tech firms, educational bodies and sponsors to promote STEM initiatives including scholarships, paid internships, and entry level graduate roles.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/cacee-logo-04349851-a5ef1d11.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><span><a href="http://www.cacee.com/" target="_blank" target="_blank" rel="noopener">Canadian Association of Career Educators and Employers (CACEE)</a>&nbsp;| <a href="mailto:membership@cacee.com" target="_blank" target="_blank" rel="noopener">membership@cacee.com</a> | +1 416 929 5156</span></p><p>CACEE is an association that fosters the essential networking partnership between Canadian educational institutions and employers, with members representing almost every Canadian university, many colleges, and employers across Canada. CACEE consistently provides valuable networking opportunities, professional development and education to employers and career service professionals across Canada.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-ca-anz-023cb6a6-ef05f4cb.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><span><a href="http://charteredaccountantsanz.com/" target="_blank" target="_blank" rel="noopener">Chartered Accountants Australia and New Zealand</a>&nbsp;| <a href="mailto:service@charteredaccountantsanz.com" target="_blank" target="_blank" rel="noopener">service@charteredaccountantsanz.com</a> | 1300 137 322</span></p><p>Chartered Accountants Australia and New Zealand (CA ANZ) represents more than 140,000 financial professionals, supporting them to make a difference to the businesses, organisations and communities in which they work and live. Chartered Accountants are known as Difference Makers. The depth and breadth of their expertise helps them to see the big picture and chart the best course of action.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-cpa-australia-307494d0-5cf45fdd.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://www.cpaaustralia.com.au/" target="_blank" target="_blank" rel="noopener">CPA Australia</a>&nbsp;|&nbsp;<a href="mailto:becomeacpa@cpaaustralia.com.au" target="_blank" target="_blank" rel="noopener">becomeacpa@cpaaustralia.com.au</a> |&nbsp;1300 73 73 73 (within Australia) | 03 7034 9770 (outside of Australia)</p><p>CPA Australia is one of the world''s largest accounting bodies. CPA Australia has an extensive global reach with more than 173,000 members in over 100 countries and regions, supported by 20 offices around the world. The CPA designation is recognised and respected across the globe. It signifies financial, accounting and business advisory professionals of the highest training and expertise.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-engineers-australia-f44cc2fe-cb78064f.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><span><a href="https://www.engineersaustralia.org.au/business/small-medium-business#talent" target="_blank" target="_blank" rel="noopener">Engineers Australia</a>&nbsp;|&nbsp;<a href="mailto:graduates@engineersaustralia.org.au" target="_blank" target="_blank" rel="noopener">graduates@engineersaustralia.org.au</a></span></p><p>As Australia&#8217;s national body for engineering, we&#8217;re the voice and champion of our 130,000-plus members. The future of engineering is in the hands of gradates, and we help guide them to be the best they can be. Providing partners with a pipeline of ready talent along with all the materials they need to grow and realise their professional ambitions.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-experience-gold-coast-d3180814-b9ff2e76.png" alt="" title="" loading="lazy"></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><strong><a href="https://experiencegoldcoast.com/" target="_blank" target="_blank" rel="noopener">Experience Gold Coast</a>&nbsp;</strong>|&nbsp;<a href="mailto:education@experiencegoldcoast.com" target="_blank" target="_blank" rel="noopener">education@experiencegoldcoast.com</a> | 07 5592 2699</p><p>Experience Gold Coast is committed to strengthening the Gold Coast&#8217;s position as Australia&#8217;s premier visitor destination, being a home of events, a preferred place to study and delivering arts and exceptional experiences to become the Lifestyle Capital of Australia. We attract students to our city as an education destination while providing meaningful student experiences that add depth to the city''s social fabric.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-faaa-8f333a69-96baa3b4.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><span><a href="https://faaa.au/" target="_blank" target="_blank" rel="noopener">Financial Advice Association Australia</a>&nbsp;| <a href="mailto:students@faaa.au" target="_blank" target="_blank" rel="noopener">students@faaa.au</a> | 1300 337 301</span></p><p>Financial Advice Association Australia (FAAA) is the leading body proudly representing financial advice professionals in Australia. We advocate for and elevate the financial advice profession by representing the interests of our members and their clients.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-golden-key-96121a99-72b68e7d.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><span><a href="https://www.goldenkey.org/apac-prospects-page/" target="_blank" target="_blank" rel="noopener">Golden Key International Honour Society</a>&nbsp;| <a href="mailto:apac@goldenkey.org" target="_blank" target="_blank" rel="noopener">apac@goldenkey.org</a> | 02 8332 4500</span></p><p>The Golden Key International Honour Society is the world&#8217;s largest collegiate honour society, bringing together high-achieving undergraduate and graduate students from around the world. Our members are recognised for their dedication, academic excellence, and commitment to success. Golden Key offers exclusive access to career resources, professional development opportunities, and a global network that enables members to stand out from their competition.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-ise-7ec09f62-c46202e5.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><span><a href="http://www.ise.org.uk/" target="_blank" target="_blank" rel="noopener">Institute of Student Employers (ISE)</a><strong>&nbsp;</strong>| <a href="mailto:membership@ise.org.uk" target="_blank" target="_blank" rel="noopener">membership@ise.org.uk</a> | +44 20 4579 4500</span></p><p>Our role is to empower organisations to maximise the success of their business by recruiting and developing students transitioning through a range of education pathways. We achieve this by bringing together Employers, the Education Sector and Solution Providers. We provide leadership and support across all entry level programmes that support new entrants, career changers, reskilling and upskilling.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-kinectaus-0042a918-2b40f3d0.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><span><a href="http://www.kinect.org.au/" target="_blank" target="_blank" rel="noopener">KinectAUS</a>&nbsp;| <a href="mailto:director@kinect.org.au" target="_blank" target="_blank" rel="noopener">director@kinect.org.au</a></span></p><p>KinectAUS is a non-profit organisation dedicated to strengthening Australia&#8217;s defence industry by forging pathways into STEM and breaking industry stigma through passion and individuality. We achieve this by inspiring future engineers, attracting graduates to defence careers, and engaging current graduates with exclusive development and networking opportunities.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-lgpro-5002ac35-6b29a867.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><span><a href="https://www.lgpro.com/" target="_blank" target="_blank" rel="noopener">Local Government Professionals</a>&nbsp;| <a href="mailto:info@lgpro.com" target="_blank" target="_blank" rel="noopener">info@lgpro.com</a></span></p><p>LGPro is the member association and leading voice for people working in local government in Victoria, providing leadership, professional development and representation in the pursuit of excellence.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/nagcas-logo-56bbc5e6-ed076132.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><span><a href="https://www.nagcas.org.au/" target="_blank" target="_blank" rel="noopener">National Association of Graduate Career Advisory Services (NAGCAS)</a>&nbsp;| <a href="mailto:info@nagcas.org.au" target="_blank" target="_blank" rel="noopener">info@nagcas.org.au</a></span></p><p>NAGCAS is Australia&#8217;s peak professional body for career development in the higher and tertiary education sector. Our members are professionals working in the student career development, employability and graduate employment space. NAGCAS promotes an environment of professional collegiality and collaboration for experts working to support the career development learning, employability and graduate employment of students engaged in higher education learning.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-nace-eff20b64-b3348a92.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><span><a href="https://www.naceweb.org/" target="_blank" target="_blank" rel="noopener">National Association of Colleges and Employers (NACE)</a>&nbsp;|&nbsp;<a href="mailto:customerservice@naceweb.org" target="_blank" target="_blank" rel="noopener">customerservice@naceweb.org</a></span></p><p>The National Association of Colleges and Employers empowers and connects the community of professionals who support, develop, and employ the college-educated workforce. NACE provides high-quality resources and research; networking and professional development opportunities; and standards, ethics, advocacy, and guidance on key issues.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/nzage-logo-1c921847-0a717a0b.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><span><a href="http://www.nzage.co.nz/" target="_blank" target="_blank" rel="noopener">New Zealand Association of Graduate Employers (NZAGE)</a>&nbsp;| <a href="mailto:info@nzage.co.nz" target="_blank" target="_blank" rel="noopener">info@nzage.co.nz</a></span></p><p>The NZAGE is the industry body supporting New Zealand organisations to deliver world-class, best-practice early careers programmes for graduates, interns and other early talent. We work with employers, industry groups and service providers across the public and private sectors to advance early talent recruitment and development.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/sagea-b0f85f10-d2908ef5.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><span><a href="http://www.sagea.org.za/" target="_blank" target="_blank" rel="noopener">South African Graduate Employers Association (SAGEA)</a>&nbsp;| <a href="mailto:webmaster@sagea.org.za" target="_blank" target="_blank" rel="noopener">webmaster@sagea.org.za</a></span></p><p>SAGEA strives to be the voice of the South African Graduate Employer. We are a community of professionals who specialise in attracting, recruiting, developing and retaining graduate talent. We provide the opportunity to network with like-minded individuals, access the latest resources and insights, and learn from global best practice to elevate the field of graduate employment in South Africa.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-study-queensland-d61efee3-07453110.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://www.studyqueensland.qld.gov.au/" target="_blank" target="_blank" rel="noopener">Study Queensland</a>&nbsp;|&nbsp;<a href="mailto:studyqueensland@tiq.qld.gov.au" target="_blank" target="_blank" rel="noopener">studyqueensland@tiq.qld.gov.au</a></p><p>Study Queensland is a specialist business unit within Trade and Investment Queensland that provides strategic leadership to the International Education and Training (IET) sector in Queensland. Our aims are to build a strong and sustainable IET sector, promote Queensland as a premier study destination, provide grant funding to five regional study clusters across the state, and enhance the international student experience with employability initiatives.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-studyadelaide-438b11b5-377fcebf.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><span><a href="https://studyadelaide.com/" target="_blank" target="_blank" rel="noopener">StudyAdelaide</a>&nbsp;|&nbsp;<a href="mailto:enquiries@studyadelaide.com" target="_blank" target="_blank" rel="noopener">enquiries@studyadelaide.com</a> | 08 8226 0022</span></p><p>StudyAdelaide is a partnership between the South Australian Government and over 50 education institutions, working to increase awareness of Adelaide as a preferred international study destination. By providing information and assistance before and after their arrival, StudyAdelaide supports students to have a rewarding experience while they are in South Australia.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-studyperth-08aa6b5f-eeee51e3.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><span><a href="https://www.studyperth.com.au/" target="_blank" target="_blank" rel="noopener">StudyPerth</a>&nbsp;| <a href="mailto:admin@studyperth.com.au" target="_blank" target="_blank" rel="noopener">admin@studyperth.com.au</a> | 08 6244 1640</span></p><p>Here at StudyPerth, we want all international students to have the same great opportunity to live, learn and launch their education and training in the beautiful city of Perth. Working in collaboration with educational institutions, government and other stakeholders, we&#8217;re helping to position Perth as an internationally recognised study destination, offering productive learning pathways in a welcoming and vibrant location.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-acce-87b4a90c-69339d9c.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><span><a href="https://acce.org.au/" target="_blank" target="_blank" rel="noopener">The Australian Centre for Career Education (ACCE)</a>&nbsp;|&nbsp;<a href="mailto:admin@acce.org.au" target="_blank" target="_blank" rel="noopener">admin@acce.org.au</a>&nbsp;| 03 9433 8000</span></p><p>The Australian Centre for Career Education is a national career education subject association, subject expert, and endorsed training provider of career practitioners by the peak industry body, The Career Industry Council of Australia (CICA). We are a not-for-profit educational charity and thought leader in career education and development. Our mission is the advancement of career development and education for the public benefit of all Australians. We have a national focus on the development and delivery of high-quality career resources, training and consulting services across Australia.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-api-09068878-1810915d.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><span><a href="https://api.edu.au/" target="_blank" target="_blank" rel="noopener">The Australian Power Institute</a>&nbsp;|&nbsp;<a href="mailto:info@api.edu.au" target="_blank" target="_blank" rel="noopener">info@api.edu.au</a></span></p><p>The Australian Power Institute (API) is a not-for-profit national organisation backed by the power industry and focused on developing the power sector workforce for the future. The API represents major Australian power companies in providing future professional power engineering capability whose vision is to deliver a sustainable supply of highly skilled power engineering professionals working effectively to meet the challenges of Australia&#8217;s emerging energy future and to support the technical and commercial success of member companies in the energy sector.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-the-law-society-of-nsw-ac5ec70c-a6179927.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><span><a href="https://www.lawsociety.com.au/" target="_blank" target="_blank" rel="noopener">The Law Society of New South Wales</a>&nbsp;|&nbsp;<a href="mailto:lawsociety@lawsociety.com.au" target="_blank" target="_blank" rel="noopener">lawsociety@lawsociety.com.au</a></span></p><p>The Law Society of New South Wales is the co-regulator of the legal profession in NSW, alongside the Office of the NSW Legal Services Commissioner. They enforce professional standards, license solicitors to practise, investigate complaints and administer discipline to ensure the public are served by ethical and responsible solicitors. In addition, they are the largest membership organisation for solicitors in the state representing the interests of more than 33,000 members. They act as the voice of the profession and provide guidance and support through all stages of practise through a number of professional and personal development events, programs, resources and publications.</p></div></div></div></div></td></tr></table></div><div ><div></div></div></div></div></div>', false, false, NULL, true);
INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('service-provider-members', 'Service Provider Members', '<div><div><div><div><table><tr><td><div><div><div ><div><h1>Join leading service providers as members of the AAGE</h1></div></div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td><td><div></div></td><td><div><div><div ><div></div></div></div></div></td></tr></table></div></div></div></div><!-- /content zone --><!-- footer zone --><div><div><div><div ><div><p>Service Provider Members</p></div></div><div ><div><p>Our Service Provider Associate Members provide important services to the graduate recruitment and development industry. If your business isn''t listed below, join now and become a valued member of our community.</p></div></div><div><table><tr><td><div><div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td><td><div></div></td><td></td></tr></table></div><div ><div><p>Assessment and Testing</p></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-amberjack-4e74d910-73bf2dff.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://weareamberjack.com.au/" target="_blank" target="_blank" rel="noopener"><strong>Amberjack Global</strong></a>&nbsp;| 0411 115 134</p><p>Smarter talent journeys. Infinite possibilities. Amberjack Global (formally Fusion Graduate Consultancy) delivers expert insight, intelligent systems, and human connections to transform attraction, assessment, recruitment, and development for Early Careers.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-be-challenged-172766ff-37a5985d.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="http://www.bechallenged.com.au/" target="_blank" target="_blank" rel="noopener"><strong>Be Challenged</strong></a>&nbsp;|1300 723 476</p><p>At Be Challenged, we work with our clients to &#8216;Build The Buzz&#8217; of their teams. In delivering our programs, we support the enhancement of culture and personal development, increasing engagement and morale.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-cappfinity-f27e9c28-2ca0d8b6.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><strong><a href="http://www.cappfinity.com/" target="_blank" target="_blank" rel="noopener">Cappfinity</a>&nbsp; </strong>|<strong>&nbsp;</strong><a href="mailto:dpo@cappfinity.com" target="_blank" target="_blank" rel="noopener">dpo@cappfinity.com</a></p><p>Since 2005, Cappfinity has helped organisations like Accenture, Latham &amp; Watkins, Ernst &amp; Young, Expedia, and the United Nations place candidates and employees in positions where they can use their skills and strengths to deliver value and meet business objectives.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/0-1-criteria-logo-4009da35-faabee40.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><strong><a href="https://www.criteriacorp.com/" target="_blank" target="_blank" rel="noopener">Criteria</a>&nbsp;</strong> |<strong>&nbsp;</strong><a href="mailto:au.customersupport@criteriacorp.com" target="_blank" target="_blank" rel="noopener">au.customersupport@criteriacorp.com</a></p><p>Criteria empowers companies of all sizes to hire and develop top talent with assessments, interviews and employee development resources that are grounded in science and designed to engage candidates, highlight potential, reduce bias and drive superior outcomes. Uncover valuable insights throughout the employee journey with a user-friendly, comprehensive suite of tools, thoughtfully designed to help companies make better talent decisions, faster. Engage your candidates, streamline your process, increase productivity, reduce turnover and build high-performing teams. Achieve Talent Success.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/0-1-gradsift-logo-3e1e81f3-bdf1bb50.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://au.gradsift.com/" target="_blank" target="_blank" rel="noopener">GradSift</a><strong>&nbsp;</strong>|<strong>&nbsp;</strong>0417 229 152</p><p>Screen and shortlist early careers talent 10x faster, using behavioural-science biodata &#8211; past experiences, behaviours and achievements, to predict performance potential. An AI-resilient assessment with data collected objectively via profile, not a resume. Use as an assessment or an integrated ATS with included video and optional testing. Optimised candidate experience, empowered hiring managers and dramatically reduced recruiter workload.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-hirevue-b5394840-08335cbc.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><table><tbody><tr><td></td><td><p><strong><a href="https://www.hirevue.com/" target="_blank" target="_blank" rel="noopener">HireVue</a></strong><br><br>HireVue is a talent experience platform designed to automate workflows and make scaling hiring easy. Improve how you engage, screen and hire talent with text recruiting, assessments, and video interviewing software.</p></td></tr></tbody></table></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/pbc-logo-671b4116-64e4e5c0.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="http://www.peterberry.com.au/" target="_blank" target="_blank" rel="noopener"><strong>Peter Berry Consultancy</strong></a>&nbsp;| 03 8629 5100</p><p>Hogan has more than 30 years of experience providing cutting-edge assessment and consulting solutions to some of the world&#8217;s largest companies, including over half the Fortune 500.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-shl-logo-29d2ce17-1169346d.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://www.shl.com/" target="_blank" target="_blank" rel="noopener"><strong>SHL</strong></a>&nbsp;| <a href="mailto:learnmore@shl.com" target="_blank" target="_blank" rel="noopener">learnmore@shl.com</a>&nbsp;| 1800 091 846</p><p>SHL is the global leader in assessments and talent analytics, with the largest dataset and benchmark of graduates in Australia and around the world.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/logo-header-bbd7ce50-2caf2244.png" loading="lazy"></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://www.testgrid.com/" target="_blank" target="_blank" rel="noopener"><strong>Testgrid</strong></a>&nbsp;| 1300 878 473</p><p>Pre-employment psychometric assessments helping you match your company&#8217;s needs with the right person for the role.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p>Coaching, Education and Work Experience for Students</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-albright-institute-of-business-and-language-ebf40da3-54e993dc.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://albrightinstitute.edu.au/" target="_blank" target="_blank" rel="noopener"><strong>Albright Institute of Business and Language</strong></a> &nbsp;| <a href="https://albrightinstitute.edu.au/contact-us/" target="_blank" target="_blank" rel="noopener">Contact us</a></p><p>Albright Institute is more than just a place to learn, with Campuses in Melbourne, Sydney, Brisbane and Adelaide. We offer ELICOS, Vocational and Professional Year courses to students from all around the world and equip you with the employability skills and knowledge required to kickstart your successful career.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-aussizz-logo-714b3f95-0e71d14f.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://www.aussizzgroup.com/sydney/" target="_blank" target="_blank" rel="noopener"><strong>Aussizz Migration &amp; Education Consultants</strong></a>&nbsp;| <a href="mailto:sydney.marketing@aussizzgroup.com" target="_blank" target="_blank" rel="noopener">sydney.marketing@aussizzgroup.com</a> | 0412 480 443</p><p>Aussizz Group is a consortium of more than 55 + Registered Migration Agents, specialising in facilitating global mobility, ensuring immigration compliance and providing strategic immigration planning for individuals and organisations. We have been a leader in Australian immigration and visa services, guiding skilled professionals and academic aspirants through the dynamic Australian immigration landscape with expert visa and education planning.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/0-1-brightworks-logo-f27a2a75-3bbfa96b.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://brightworks.net.au/" target="_blank" target="_blank" rel="noopener"><strong>Brightworks</strong></a>&nbsp;| 0422 868 649</p><p>Brightworks works with companies to develop award-winning early career programs. We support all facets of the end-to-end lifecycle from program strategy and design, outsourced marketing and recruitment, and tailored learning and development programs, all designed to attract, develop and retain the very best in emerging talent and deliver business results.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-careerseekers-7e7c3c42-442b45c1.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><div><p><strong><a href="https://careerseekers.org.au/" target="_blank" target="_blank" rel="noopener">CareerSeekers</a></strong></p><p>CareerSeekers is a non-profit social enterprise that works with employers to create paid professional placements for people that have come to Australia as refugees or asylum seekers. Our participants bring expertise, fresh perspectives, and resilience, but systemic barriers often keep them from meaningful employment.</p></div></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-careertrackers-3a4ee20f-1fe03f93.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><div><p><strong><a href="https://careertrackers.org.au/" target="_blank" target="_blank" rel="noopener">CareerTrackers</a>&nbsp;</strong><span>|</span><strong>&nbsp;</strong><a href="mailto:info@ct.org.au" target="_blank" target="_blank" rel="noopener">info@ct.org.au</a></p><p>CareerTrackers is a national purpose-driven organisation that supports pre-professional Indigenous university students and links them with employers to participate in paid, multi-year internships. CareerTrackers students complete university with high marks, industry experience and bright futures.</p></div></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-ea-eea-logo-471b00d4-53823ce6.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><div><p><strong><a href="https://eea.org.au/" target="_blank" target="_blank" rel="noopener">Engineering Education Australia</a>&nbsp;</strong><span>|</span><strong>&nbsp;</strong><a href="mailto:development@eea.org.au" target="_blank" target="_blank" rel="noopener">development@eea.org.au</a></p><p>Engineering Education Australia partners with organisations to create customised professional development programs that enhance the skills and capabilities of engineers and related professions. We offer end-to-end solutions, from strategic program design and tailored training to ongoing support, all aimed at upskilling, developing, and retaining top talent, ensuring your workforce stays ahead of industry trends and contributes to your organisation''s long-term success.</p></div></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-holberton-school-australia-logo-2573661d-1ee597fa.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><div><p><strong><a href="https://holbertonschool.com.au/" target="_blank" target="_blank" rel="noopener">Holberton School Australia</a>&nbsp;</strong><span>| <a href="mailto:contact@holbertonschool.com.au" target="_blank" target="_blank" rel="noopener">contact@holbertonschool.com.au</a></span></p><p>Holberton School Australia offers industry-aligned software engineering education, equipping career changers with hands-on skills to thrive in tech. Our intensive program fosters problem-solving, collaboration, and real-world coding expertise.</p></div></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-inner-eastern-llen-7113a159-ca779b6e.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://iellen.org.au/" target="_blank" target="_blank" rel="noopener"><strong>Inner Eastern LLEN</strong></a> | <a href="mailto:iellen@iellen.org.au" target="_blank" target="_blank" rel="noopener">iellen@iellen.org.au</a> | 03 9510 5444</p><p>The Inner Eastern Local Learning and Employment Network (IELLEN) is a charity organisation that provides activities, services and programs (in partnership with schools, business and industry, LGAs and community organisations) to help improve lives through education, employment and welfare support, for vulnerable and at-risk people, especially youth. The IELLEN is a School to Work Program provider. We are one of 31 LLENs across Victoria contracted by the Department of Education to provide this Program. Supporting 44 local schools, we engage with business and industry to support access to work-based learning opportunities and career related activities to showcase various careers and post school pathways.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-international-internships-a5db243f-6f20c56f.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><div><p><strong><a href="https://www.internationalinternships.com.au/" target="_blank" target="_blank" rel="noopener">International Internships</a>&nbsp;</strong><span>| <a href="mailto:info@internationalinternships.com.au" target="_blank" target="_blank" rel="noopener">info@internationalinternships.com.au</a></span></p><p>International Internships is an Australian-based provider of work-integrated learning programs, offering internships and study intensives in Indonesia across various fields. With over 15 years of experience, we focus on real-world challenges, fostering intercultural competence, and supporting students to earn academic credit while gaining practical skills and professional networks.</p></div></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-mtc-futureready-514005d1-1cb430b5.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://www.mtcfutureready.org.au/" target="_blank" target="_blank" rel="noopener"><strong>MTC FutureReady</strong></a> | <a href="mailto:info@mtcfutureready.org.au" target="_blank" target="_blank" rel="noopener">info@mtcfutureready.org.au</a> | 1300 232 663</p><p>MTC FutureReady is a social enterprise that&#8217;s here to help people take practical steps towards real progress. Our targeted training programs, meaningful employment services and unbeatable support are all designed to bring about fresh possibilities and drive life-changing transformation. Each year we support almost 22,000 people across New South Wales, Queensland, Victoria and the ACT who are vulnerable and facing barriers to opportunity with new skills, confidence, and possibilities.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-multicultural-community-centre-6926dc04-0359bca3.png" loading="lazy"></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://mccbrisbane.org/" target="_blank" target="_blank" rel="noopener"><strong>Multicultural Community Centre</strong></a> | <a href="mailto:info@mccbrisbane.org" target="_blank" target="_blank" rel="noopener">info@mccbrisbane.org</a> | 07 3257 1868</p><p>Transforming Lives. Changing Destinies.</p><p>MCC is a non-for-profit organisation that supports culturally diverse communities through practical programs, advocacy, and community initiatives.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-nit-56bd5222-dd235b3d.png" alt="" title="" loading="lazy"><p><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://www.nitaustralia.edu.au/" target="_blank" target="_blank" rel="noopener"><strong>National Institute of Technology</strong></a> | <a href="mailto:enquiries@nitaustralia.edu.au" target="_blank" target="_blank" rel="noopener">enquiries@nitaustralia.edu.au</a> | 1300 111 909</p><p>National Institute of Technology is a leading education and training provider in Information Technology, Engineering, and Professional Year programs. NIT is also a leading ICT and Engineering internship provider, with established agreements with over 200 employer organisations, offering valuable industry-based internship opportunities to students.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-navitas-eb99c2c4-6ffbaff7.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="http://www.navitas.com/" target="_blank" target="_blank" rel="noopener"><strong>Navitas Professional</strong></a></p><p>Navitas is a leading global education provider that has helped generations of learners transform their lives through education.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-readygrad-4c9118cd-b80f841c.png" alt="" title="" loading="lazy"><br></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://www.readygrad.com.au/" target="_blank" target="_blank" rel="noopener"><strong>ReadyGrad</strong></a>&nbsp;| 03 7034 4411</p><p>Readygrad is a proud leader in the graduate employability space. We see a world where every graduate has the right skills and experience to pursue the career(s) of their choice. We lift the employability of tertiary students and graduates through relevant and industry-informed work-readiness training and work experience programs.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/tafe-sa-d62de3ed-f32bb00f.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><strong><a href="https://www.tafesa.edu.au/" target="_blank" target="_blank" rel="noopener">TAFE SA</a></strong> | <a href="mailto:susan.hervey@tafesa.edu.au" target="_blank" target="_blank" rel="noopener">susan.hervey@tafesa.edu.au</a> | 08 8463 5082</p><p>TAFE SA is South Australia&#8217;s largest vocational education and training provider. We deliver job-focused training across a range of industries from entry-level certificates to bachelor degrees, at locations across the state. TAFE SA&#8217;s role as the public provider of vocational education and training (VET) is to ensure all South Australians have access to quality education and skills training across the state. With the growth in demand for skills in current, new and emerging industries, the importance of addressing skills shortages and increasing our skilled workforce has never been more important. It is the programs that TAFE SA delivers to target diverse student cohorts, right across the state that ensures current and future generations have the skills they need. With courses aligned to the needs of the state&#8217;s current and future workforce, this ensures TAFE SA is responsive, relevant and future focused.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-the-careers-department-logo-ef915caa-303c4609.png" alt="" title="" loading="lazy"><br></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://www.thecareersdepartment.com/" target="_blank" target="_blank" rel="noopener"><strong>The Careers Department</strong></a></p><p>The Careers Department unlocks career exposure for students, teachers and parents. Our online platform has helped 1.4 million Australian families and is used daily in over 680 high schools and 1,000 primary schools</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-trellis-collective-7ba2ace9-e02706e0.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="http://trelliscollective.com/" target="_blank" target="_blank" rel="noopener"><strong>Trellis Collective</strong></a>&nbsp;| 0457 438 805</p><p>Trellis Collective works with organisations in male-dominated industries to increase the retention and participation of their early career women, contributing to a more robust pipeline of female talent while meeting DEI targets. Offering an organisation-wide approach, Trellis engages companies through insightful strategic consulting, effective professional development programs for both early career women and their managers, and the provision of data-driven recommendations to affect long-lasting change.</p></div></div></div></div></td></tr></table></div><div ><div><p>Disability Services</p></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-aust-disability-network-0224fffd-0434cb6c.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://and.org.au/" target="_blank" target="_blank" rel="noopener"><strong>Australian Disability Network</strong></a>&nbsp;| 1300 363 645</p><p>The Australian Disability Network brings together the experience and knowledge of hundreds of Australia&#8217;s leading organisations who include people with disability as their employees and customers.</p></div></div></div></div></td></tr></table></div><div ><div><p>Graduate Development, Training and Wellbeing</p></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-amberjack-4e74d910-73bf2dff.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://weareamberjack.com.au/" target="_blank" target="_blank" rel="noopener"><strong>Amberjack Global</strong></a>&nbsp;| 0411 115 134</p><p>Smarter talent journeys. Infinite possibilities. Amberjack Global (formally Fusion Graduate Consultancy) delivers expert insight, intelligent systems, and human connections to transform attraction, assessment, recruitment, and development for Early Careers.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-be-challenged-172766ff-37a5985d.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="http://www.bechallenged.com.au/" target="_blank" target="_blank" rel="noopener"><strong>Be Challenged</strong></a>&nbsp;|1300 723 476</p><p>At Be Challenged, we work with our clients to &#8216;Build The Buzz&#8217; of their teams. In delivering our programs, we support the enhancement of culture and personal development, increasing engagement and morale.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/0-1-brightworks-logo-f27a2a75-3bbfa96b.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://brightworks.net.au/" target="_blank" target="_blank" rel="noopener"><strong>Brightworks</strong></a>&nbsp;| 0422 868 649</p><p>Brightworks works with companies to develop award-winning early career programs. We support all facets of the end-to-end lifecycle from program strategy and design, outsourced marketing and recruitment, and tailored learning and development programs, all designed to attract, develop and retain the very best in emerging talent and deliver business results.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/0-1-dbl-48a1d3ef-7361b491.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="http://www.developmentbeyondlearning.com/" target="_blank" target="_blank" rel="noopener"><strong>Development Beyond Learning</strong></a>&nbsp;| 02 8898 9703</p><p>Founded in Australia, Development Beyond Learning (DBL) is in the specialist field of graduate learning and development. An award-winning team using behavioural science to future-proof businesses and people.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-elephant-ed-9889a58a-36ccd2ef.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://www.elephanted.com.au/" target="_blank" target="_blank" rel="noopener"><strong>Elephant Ed</strong></a> | 1300 006 440</p><p>Elephant Ed sends engaging and dynamic facilitators to workplaces across Australia to deliver preventative workshops around sexual harassment, discrimination and appropriate workplace behaviour. Elephant Ed&#8217;s workshops are high-impact and interactive, sharing practical and evidence-based strategies to craft an environment where your employees feel safe, empowered and supported.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-ea-eea-logo-471b00d4-53823ce6.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><div><p><strong><a href="https://eea.org.au/" target="_blank" target="_blank" rel="noopener">Engineering Education Australia</a>&nbsp;</strong><span>|</span><strong>&nbsp;</strong><a href="mailto:development@eea.org.au" target="_blank" target="_blank" rel="noopener">development@eea.org.au</a></p><p>Engineering Education Australia partners with organisations to create customised professional development programs that enhance the skills and capabilities of engineers and related professions. We offer end-to-end solutions, from strategic program design and tailored training to ongoing support, all aimed at upskilling, developing, and retaining top talent, ensuring your workforce stays ahead of industry trends and contributes to your organisation''s long-term success.</p></div></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-learning-ventures-99fdda10-d4f0a49a.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://learningventures.com.au/" target="_blank" target="_blank" rel="noopener"><strong>Learning Ventures</strong></a>&nbsp;| 0419 292 082</p><p>Learning Ventures was established in 2011 with a clear purpose; to design and deliver high impact leadership and management development programs and organisational development services.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-readygrad-4c9118cd-b80f841c.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://readygrad.com.au/" target="_blank" target="_blank" rel="noopener"><strong>Readygrad</strong></a>&nbsp;| 03 7034 4411</p><p>Readygrad is a proud leader in the graduate employability space. We see a world where every graduate has the right skills and experience to pursue the career(s) of their choice. We lift the employability of tertiary students and graduates through relevant and industry-informed work-readiness training and work experience programs.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-the-career-conversation-a4a9da25-97734900.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://www.thecareerconversation.com/" target="_blank" target="_blank" rel="noopener"><strong>The Career Conversation</strong></a>&nbsp;| <a href="mailto:info@thecareerconversation.com" target="_blank" target="_blank" rel="noopener">info@thecareerconversation.com</a></p><p>We specialise in early career engagement, nurturing connections from initial interest to early employment stages. We strengthen work readiness with bite-sized learning, reinvigorate employer brands, and foster strong relationships with Gen Z talent and their leaders.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-the-real-leadership-company-bdbfa3b4-9fa00a41.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><strong><a href="https://www.therealleadershipcompany.com.au/" target="_blank" target="_blank" rel="noopener">The Real Leadership Company</a>&nbsp;</strong><span>|</span><strong>&nbsp;</strong><span><a href="mailto:saul@therlc.com.au" target="_blank" target="_blank" rel="noopener">saul@therlc.com.au</a> |&nbsp;</span>0419 387 844</p><p>Founded in 2017, The Real Leadership delivers a powerful combination of bespoke workshops and one-on-one coaching to help clients unlock high performance. At the heart of the company is founder Saul Wajntraub, who brings over 10 years of experience in designing and delivering leadership coaching programs. With more than 20 years in learning and development, Saul has facilitated over 750 workshops and logged 3,000+ coaching hours, building deep practical expertise.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-trellis-collective-7ba2ace9-e02706e0.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><div><div></div></div><div></div><div><p><strong><a href="http://trelliscollective.com/" target="_blank" target="_blank" rel="noopener">Trellis Collective</a>&nbsp;</strong>|&nbsp;0457 438 805</p><p>Trellis Collective works with organisations in male-dominated industries to increase the retention and participation of their early career women, contributing to a more robust pipeline of female talent while meeting DEI targets. Offering an organisation-wide approach, Trellis engages companies through insightful strategic consulting, effective professional development programs for both early career women and their managers, and the provision of data-driven recommendations to affect long-lasting change.</p></div></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p>Graduate Program Design, Strategy and Process Outsourcing</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-amberjack-4e74d910-73bf2dff.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://weareamberjack.com.au/" target="_blank" target="_blank" rel="noopener"><strong>Amberjack Global</strong></a>&nbsp;| 0411 115 134</p><p>Smarter talent journeys. Infinite possibilities. Amberjack Global (formally Fusion Graduate Consultancy) delivers expert insight, intelligent systems, and human connections to transform attraction, assessment, recruitment, and development for Early Careers.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-be-challenged-172766ff-37a5985d.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="http://www.bechallenged.com.au/" target="_blank" target="_blank" rel="noopener"><strong>Be Challenged</strong></a>&nbsp;|1300 723 476</p><p>At Be Challenged, we work with our clients to &#8216;Build The Buzz&#8217; of their teams. In delivering our programs, we support the enhancement of culture and personal development, increasing engagement and morale.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/0-1-brightworks-logo-f27a2a75-3bbfa96b.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><div><p><strong><a href="https://brightworks.net.au/" target="_blank" target="_blank" rel="noopener">Brightworks</a>&nbsp;</strong>|<strong>&nbsp;</strong><a href="mailto:hello@brightworks.net.au" target="_blank" target="_blank" rel="noopener">hello@brightworks.net.au</a></p><p>We excel at implementing best practice strategies, developing innovative programs, and conducting dynamic strategy and program reviews. Our mission is to tailor fully customised solutions for your early careers programs, ensuring they spark excitement and success for organisations.</p></div></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-chandler-macleod-f1bd41a8-4d9d9055.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><div><p><strong><a href="http://www.chandlermacleod.com/" target="_blank" target="_blank" rel="noopener">Chandler Macleod Group</a></strong><span>|</span><strong>&nbsp;</strong>0412 534 773</p><p>With over 60 years'' experience, Chandler Macleod is Australia''s leading provider of graduate recruitment RPO services. We provide a fully tailored recruitment strategy based on complete understanding of what success looks like.</p></div></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-dfp-recruitment-cf2167df-9072f102.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><div><p><strong><a href="https://www.dfp.com.au/" target="_blank" target="_blank" rel="noopener">DFP Recruitment</a>&nbsp;</strong><span>|</span><strong>&nbsp;</strong>03 8632 9900</p><p>DFP Recruitment Services is one of Australia&#8217;s leading recruitment companies. Established in 1981, DFP has developed a reputation for delivering specialist services in temporary, permanent and volume staffing services combined with ethics, integrity and professionalism.</p></div></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-ea-eea-logo-471b00d4-53823ce6.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><div><p><strong><a href="https://eea.org.au/" target="_blank" target="_blank" rel="noopener">Engineering Education Australia</a>&nbsp;</strong><span>|</span><strong>&nbsp;</strong><a href="mailto:development@eea.org.au" target="_blank" target="_blank" rel="noopener">development@eea.org.au</a></p><p>Engineering Education Australia partners with organisations to create customised professional development programs that enhance the skills and capabilities of engineers and related professions. We offer end-to-end solutions, from strategic program design and tailored training to ongoing support, all aimed at upskilling, developing, and retaining top talent, ensuring your workforce stays ahead of industry trends and contributes to your organisation''s long-term success.</p></div></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-give-a-grad-a-go-2907d2e9-39b72d34.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><div><div><p><strong><a href="https://www.giveagradago.com/" target="_blank" target="_blank" rel="noopener">Give A Grad A Go</a></strong><br></p><p>We are passionate about supporting graduates and early career professionals in finding and building careers they will love, whilst helping businesses to enhance their talent attraction and hire their future leaders.</p></div></div></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/0-1-gradsift-logo-3e1e81f3-bdf1bb50.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://au.gradsift.com/" target="_blank" target="_blank" rel="noopener">GradSift</a><strong>&nbsp;</strong>|<strong>&nbsp;</strong>0417 229 152</p><p>Screen and shortlist early careers talent 10x faster, using behavioural-science biodata &#8211; past experiences, behaviours and achievements, to predict performance potential. An AI-resilient assessment with data collected objectively via profile, not a resume. Use as an assessment or an integrated ATS with included video and optional testing. Optimised candidate experience, empowered hiring managers and dramatically reduced recruiter workload.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-hoban-recruitment-09003efa-3394b514.png" alt="" title="" loading="lazy"><img src="https://aage.com.au/resources/Pictures/1.0%20Hoban.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><strong><a href="http://www.hoban.com.au/" target="_blank" target="_blank" rel="noopener">HOBAN Recruitment</a></strong><span>|</span><strong>&nbsp;</strong>1300 560 272 </p><p>Since 1965, HOBAN Recruitment has been creating innovative recruitment solutions. HOBAN Recruitment&#8217;s expertise encompasses permanent and temporary recruitment in white-collar, industrial, and commercial sectors and Government organisations.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-h1-db7eddd5-70d02333.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><div><div><p><strong><a href="http://horizonone.com.au/" target="_blank" target="_blank" rel="noopener">HorizonOne Recruitment</a>&nbsp;</strong><span>|</span><strong>&nbsp;</strong>02 6108 4878 &nbsp;</p><p></p><p>We''re HorizonOne, Canberra''s recruitment specialists. We connect people to purpose, teams to talent and motivations to opportunities. We ask the right questions to get you the right outcome. Let''s talk.</p></div></div></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-hudson-02c1b6f5-9fca5a9a.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><strong><a href="http://au.hudson.com/" target="_blank" target="_blank" rel="noopener">Hudson</a>&nbsp;</strong><span>|</span><strong>&nbsp;</strong>07 3185 5355</p><p>Scaleup by Hudson is Australia&#8217;s trusted partner in high-impact assessment and large-scale talent acquisition. Our highly efficient and defendable recruitment, assessment and technology solutions are built for the biggest challenges.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-people-solutions-8aa38a7f-7cdcc92a.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><div><div><p><strong><a href="https://www.people-solutions.com.au/" target="_blank" target="_blank" rel="noopener">People Solutions</a>&nbsp;</strong><span>|</span><strong>&nbsp;</strong><span><a href="mailto:info@people-solutions.com.au" target="_blank" target="_blank" rel="noopener">info@people-solutions.com.au</a> |&nbsp;</span>08 9388 0300</p><p>As organisational development consultants, we partner with customers across Australasia, developing highly tailored, cost-effective solutions that help organisations understand the potential in their people and business, and then fulfil it.</p></div></div></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/peoplescout-a8e53fd4-e5b8d296.png" loading="lazy"></p><p><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><div><div><p><strong><a href="https://www.peoplescout.com.au/" target="_blank" target="_blank" rel="noopener">PeopleScout</a>&nbsp;</strong><span>|</span><strong>&nbsp;</strong>02 9561 9000</p><p>We solve complex hiring challenges through our dedicated, scalable and customisable recruitment process outsourcing, managed service provider and total workforce solutions delivery models. Whether you are in need of full-cycle RPO, contingent workforce management or a blend of both, PeopleScout has you covered.</p></div></div></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-readygrad-4c9118cd-b80f841c.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><div><p><span><a href="https://readygrad.com.au/" target="_blank" target="_blank" rel="noopener">Readygrad</a>&nbsp;|</span><strong>&nbsp;</strong>03 7034 4411</p><p>Readygrad is a proud leader in the graduate employability space. We see a world where every graduate has the right skills and experience to pursue the career(s) of their choice. We lift the employability of tertiary students and graduates through relevant and industry-informed work-readiness training and work experience programs.</p></div></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-tq-a365d64f-1cf4db78.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><div><div><p><strong><a href="https://tqsolutions.com.au/" target="_blank" target="_blank" rel="noopener">TQSolutions</a>&nbsp;|&nbsp;</strong><a href="mailto:hello@tqsolutions.com.au" target="_blank" target="_blank" rel="noopener">hello@tqsolutions.com.au</a></p><p><a href="mailto:hello@tqsolutions.com.au" target="_blank" target="_blank" rel="noopener"></a></p>TQ is a leading Early Talent Consulting business. We have deep expertise in Early Careers advisory including candidate attraction &amp; engagement, employer brand, recruitment solutions, assessment &amp; selection and technology.</div></div></div></div></div></div></td></tr></table></div><div ><div><p>Job Boards and Candidate Databases</p></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/0-1-symplicity-510e4a96-6b4dda32.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><strong><a href="https://careerhub.com.au/" target="_blank" target="_blank" rel="noopener">CareerHub Central / Symplicity</a></strong></p><p><strong></strong>CareerHub Central is Australia&#8217;s largest &amp; most active student recruitment network, with access to nearly 4+ millions students for early talent recruitment.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-seek-grad-c1985ca6-40f744dc.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><div><p><span><a href="http://au.gradconnection.com/" target="_blank" target="_blank" rel="noopener">SEEK Grad (formerly GradConnection)</a>&nbsp;<span>| <a href="mailto:clients@gradconnection.com" target="_blank" target="_blank" rel="noopener">clients@gradconnection.com</a></span></span></p><p>SEEK Grad (formerly GradConnection) has been connecting university graduates with top employers since being founded in 2008 by three ambitious grads. In 2019, GradConnection was acquired by job site SEEK and rebranded to SEEK Grad in 2026.</p></div></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-prosple-177bea53-95ee6e1d.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><div><div><p><strong><a href="https://prosple.com/" target="_blank" target="_blank" rel="noopener">Prosple</a></strong><br></p><p>Prosple exists to make sure all students have equal access to the best career advice and opportunities.</p></div></div></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/stem-women-7d7dcebf-bd1e3f1d.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><strong><a href="https://stemwomen.global/" target="_blank" target="_blank" rel="noopener">STEM Women</a></strong><br></p><p>STEM Women Global is an online directory of women in global working in STEM (Science, Technology, Engineering and Mathematics). STEM Women Global aims to promote gender equity in STEM by showcasing the breadth of scientific talent in the region, enabling a diverse range of women to be offered exciting opportunities to progress their careers and personal capabilities.</p></div></div></div></div></td></tr></table></div><div ><div><p>Marketing, Branding and Advertising</p></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-noble-agency-62ea0a5b-e18b4dc0.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><div><div><p><strong><a href="http://nobleagency.com.au/" target="_blank" target="_blank" rel="noopener">Noble Agency</a>&nbsp;</strong><span>|</span><strong>&nbsp;</strong>0412 675 329</p><p>Noble by name, noble by nature, we&#8217;re a creative agency built on integrity, creativity and a decade or two of experience in EVP, employer branding and marketing.</p></div></div></div></div></div></div></td></tr></table></div><div ><div><p>Technology and Software</p></div></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-groupgti-targetconnect-3636058e-0d34f0ce.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><strong><a href="https://www.targetconnect.com/educator-features" target="_blank" target="_blank" rel="noopener">GroupGTI - targetconnect</a>&nbsp;|&nbsp;</strong><a href="mailto:sokho.chong@groupgti.com" target="_blank" target="_blank" rel="noopener">sokho.chong@groupgti.com</a></p><p>Targetconnect is a unified platform designed for universities and education providers to manage career services, student support, and employer engagement in one place. It acts as a central hub for students, graduates, and organisations - offering modules for consultation bookings, events management, CRM, job and internship opportunities, skills assessments, data analytics, and more to streamline operations and enhance student outcomes.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-rare-a9a59f46-e1883d59.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><div><p><strong><a href="https://www.rarerecruitment.co.uk/" target="_blank" target="_blank" rel="noopener">Rare Recruitment</a></strong><br><br> Rare is a multi-award-winning diversity company. We provide cutting-edge data services that help our clients make better hiring decisions. We have received press coverage in the Financial Review, The Australian and Lawyers Weekly.</p></div></div></div></div></div></td></tr></table></div><div ><div></div></div></div></div></div>', false, false, NULL, true);
INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('university-members', 'University Members', '<div><div><div><div><table><tr><td><div><div><div ><div><h1>Join leading universities as&nbsp;members of the AAGE</h1></div></div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td><td><div></div></td><td><div><div><div ><div></div></div></div></div></td></tr></table></div></div></div></div><!-- /content zone --><!-- footer zone --><div><div><div><div><table><tr><td><div><div><div ><div><p>University Members</p></div></div><div ><div><p>The universities below are members of the AAGE, with most taking advantage of our Full Careers Service Membership to ensure their entire careers department can access member benefits. Don''t see your university below? We''d love to welcome you as a member. High schools are also eligible to join the AAGE.</p></div></div><div ><div><p><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/home-page-big-meet-students-911825d1-1f33b525.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><ul><li><a href="https://adelaideuni.edu.au/students/careers-and-employability/" target="_blank" rel="noopener">Adelaide University</a></li><li><a href="https://www.acu.edu.au/student-life/student-services/careers-and-employability" target="_blank" rel="noopener">Australian Catholic University</a></li><li><a href="https://bond.edu.au/current-students/opportunities/career-development-centre" target="_blank" rel="noopener">Bond University</a></li><li><a href="https://www.cqu.edu.au/student-life/new-students/student-support/careers-and-leadership" target="_blank" rel="noopener">Central Queensland University</a>