INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('industry-events', 'Industry Events', '<div><div><div><div><table><tr><td><div><div><div ><div><h1>Annual conferences for professional bodies in the early careers sector</h1></div></div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td><td><div></div></td><td></td></tr></table></div></div></div></div><!-- /content zone --><!-- footer zone --><div><div><div><div ><div><p>National Events</p></div></div><div><table><tr><td><div><div><div ><div><p>National Association of Graduate Careers Advisory Services (NAGCAS)<br></p></div></div><div ><div><p><strong>2025 NAGCAS Annual Conference</strong><br>3rd - 5th December 2025<br>Sydney, Australia</p></div></div><div ><div><p><a href="https://www.nagcas.org.au/conference" target="_blank" target="_blank" rel="noopener">Visit website</a><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://www.nagcas.org.au/" target="_blank" target="_blank" rel="noopener"><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/nagcas-logo-56bbc5e6-ed076132.png" alt="" title="" loading="lazy"></a><br></p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p>Young Professional Women Australia (YPWA)<br></p></div></div><div ><div><p><strong>Conferences, Mentoring &amp; Development Programs &amp; Free Networking Opportunities</strong>. YPWA''s priority is to provide great value events and opportunities for their community at a low cost to ensure accessibility for all to invest in their own development and live a life filled with choices and fulfilment.</p></div></div><div ><div><a href="http://www.ypwa.com.au/#!events/c1vw1" target="_blank" target="_blank" rel="noopener">Visit website</a></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://www.ypwa.com.au/#!ev