INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('members-events', 'Members'' Events', '<div><div><div><div><table><tr><td><div><div><div ><div><h1>Find out about events that our members are hosting</h1></div></div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td><td><div></div></td><td></td></tr></table></div></div></div></div><!-- /content zone --><!-- footer zone --><div><div><div><div ><div><p>Members'' Events</p></div></div><div><table><tr><td><div><div><div ><div><p>Young Professional Women Australia (YPWA)<br></p></div></div><div ><div><p><strong>Conferences, Mentoring &amp; Development Programs &amp; Free Networking Opportunities</strong>. YPWA''s priority is to provide great value events and opportunities for their community at a low cost to ensure accessibility for all to invest in their own development and live a life filled with choices and fulfilment.</p></div></div><div ><div><a href="http://www.ypwa.com.au/#!events/c1vw1" target="_blank" target="_blank" rel="noopener">Visit website</a></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><a href="https://www.ypwa.com.au/#!events/c1vw1" target="_blank" target="_blank" rel="noopener"><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/ypwa-logo-07545f2c-64721445.png" alt="" title="" loading="lazy"></a><br></p></div></div></div></div></td></tr></table></div><div><table><tr><td></td></tr></table></div></div></div></div>', false, false, NULL, true);
INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('conference', 'Conference', '<div><div><div><div><table><tr><td><div><div><div ><div><h1>Join the industry''s annual conference for early talent professionals</h1></div></div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td><td><div></div></td><td></td></tr></table></div></div></div></div><!-- /content zone --><!-- footer zone --><div><div><div><div><table><tr><td><div><div><div ><div><p>AAGE Annual Graduate Recruitment and Development Conference</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p>Wednesday 11th &#8211; Thursday 12th November 2026<br>Hilton Sydney, Australia</p></div></div><div ><div><p><strong>*Bookings close Monday 2nd November 2026*</strong></p><p>We&#8217;re excited to invite early careers professionals to the 38th Annual AAGE Graduate Recruitment and Development Conference!</p><p>In 2026, we&#8217;re evolving our format to bring you the same high-quality content, thought leadership and community connection &#8211; <strong>now in a streamlined two-day program</strong>. By starting earlier on Day 1, the schedule ensures you experience all of the hallmark elements of the AAGE Conference, from inspiring keynotes, interactive workshops, the dynamic industry expo, and opportunities to exchange ideas and best practices with your peers. The Social Evening and the AAGE Gala Dinner, featuring the 2026 AAGE Graduate Recruitment Industry Awards (AGRIAs), will remain integral highlights within the two-day program.</p><p>2026 AAGE Conference delegates also receive access upon booking their conference pass to register for our <strong>2026 AAGE Professional Development Workshops</strong> which will take place on Friday 13th November at the Hilton Sydney, immediately following the two-day conference. These half-day learning events are <strong>$350 + GST each</strong> and must be <strong>booked separately</strong> to the conference. Due to limited availability, bookings are currently <strong>ONLY</strong> available to AAGE members who are registered 2026 AAGE Conference delegates. Please note that this offer does not extend to members who have purchased tickets to the 2026 AAGE Conference social events only.</p><p><strong>The AAGE Conference remains the must-attend event for anyone shaping the future of early careers.</strong> Join us to connect with like-minded professionals, learn from leading voices and walk away with insights that will influence your programs and the talent you support.</p><p><strong>*SPECIAL OFFER* &#8211; Purchase four Full Conference Passes and get a fifth Full Conference Pass FREE! Click the registration button below for T&amp;Cs. Don''t miss this opportunity to bring more of your team to the 2026 AAGE Conference!</strong><br></p></div></div><div ><div><p><a href="/events.html" target="_blank" rel="noopener">Register now for 2026</a>&nbsp;</p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/conference-4ba57870-ba5d59e7.png" alt="" title="" loading="lazy"><br></p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p>About the conference</p></div></div><div ><div> Why attend the annual AAGE conference?</div></div><div ><div><a href="/page.html?slug=why-attend" target="_blank" rel="noopener">View now</a></div></div><div ><div> Discounted tickets for members</div></div><div ><div><p>AAGE members enjoy discounted rates on full conference passes and day passes.</p></div></div><div ><div><a href="/page.html?slug=member-benefits" target="_blank" rel="noopener">Member benefits</a></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>Celebrate excellence at the AGRIAs</p></div></div><div ><div><p>Explore our 2025 AAGE Graduate Recruitment Industry Award Winners.</p></div></div><div ><div><a href="/page.html?slug=agrias" target="_blank" rel="noopener">Learn more</a></div></div><div ><div><p>2025 Conference Program</p></div></div><div ><div><p>The 2026 program will be available in the lead up to the event.</p></div></div><div ><div><a href="https://pr-9q32ba.run402.com/_blob/assets/aage/2025-aage-conference-program-f705b1c8-1f905dd2.pdf" target="_blank" rel="noopener">View the 2025 program</a></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>Join 500+ conference<br>delegates</p></div></div><div ><div><p>Check out who is attending the 2026 conference in Sydney.</p></div></div><div ><div><p><a href="/page.html?slug=delegates" target="_blank" rel="noopener">See who is attending</a></p></div></div><div ><div><p>Meet our 2025 Sponsors and Exhibitors</p></div></div><div ><div><p>Meet the leading suppliers to the early careers industry.</p></div></div><div ><div><a href="/page.html?slug=sponsors-exhibitors" target="_blank" rel="noopener">See who attended</a></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div></div></div></div></div></td></tr></table></div></div></div></div>', false, false, NULL, true);
INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('why-attend', 'Why attend?', '<div><div><div><div><table><tr><td><div><div><div ><div><h1>Join the industry''s annual conference for early talent professionals </h1></div></div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td><td><div></div></td><td></td></tr></table></div></div></div></div><!-- /content zone --><!-- footer zone --><div><div><div><div><table><tr><td><div><div><div ><div><p>About the AAGE Conference</p></div></div><div ><div><p>The AAGE Conference is ideal for those involved with graduate recruitment and development, including human resources professionals, university careers advisors, service providers and professional associations with graduate programs.</p><p>AAGE Conferences bring delegates together to focus on broader issues impacting on the industry, to have the opportunity to learn from industry experts, discover the latest trends and to discuss ideas and solutions to handle industry challenges.</p><p>The conference format encourages the open sharing of knowledge and experience, which serves to elevate the graduate recruitment industry as an increasingly important, strategic part of a business.</p><p>Plenty of networking opportunities are offered to delegates, including discussion groups held during the course of the day sessions, a <strong>Social Evening</strong> held on the first night of the conference and our annual&nbsp;<strong>Gala Dinner</strong> held on the second night of the conference which celebrates the <strong>AAGE Graduate Recruitment Industry Awards (AGRIAs)</strong>.</p><p>2026 marks the 38th year that the AAGE has hosted a Graduate Recruitment and Development Conference in Australia.</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p>What our delegates say about attending the AAGE conference</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p>Cheryl Koe, Australian Tax Office</p></div></div><div ><div><p>"The AAGE conference is great for networking and getting an insight into the latest offerings available to graduate employers. </p><p>There is also plenty of fun and learning."</p></div></div><div ><div><p><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p>Kelly Pfeffer, Suncorp</p></div></div><div ><div><p>"Attending the conference really emphasised for me the feeling of community and how there are a lot of people in the same role as me with the same challenges.</p><p>The conference provided an opportunity for me to build my network and hear how others have overcome some of these challenges."</p></div></div><div ><div><p><br></p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div> Cathy James, Fusion Graduate Consultancy</div></div><div ><div> "The AAGE Conference is an incredible opportunity for networking and professional development, and results in a direct impact on the quality of our Internship Program."</div></div><div ><div><p><br></p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div></div></div></div></div></td></tr></table></div></div></div></div>', false, false, NULL, true);
INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('delegates', 'Delegates', '<div><div><div><div><table><tr><td><div><div><div ><div><h1>Join around 500 delegates at the annual AAGE Conference</h1></div></div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td><td><div></div></td><td><div><div><div ><div></div></div></div></div></td></tr></table></div></div></div></div><!-- /content zone --><!-- footer zone --><div><div><div><div><table><tr><td><div><div><div ><div><p>2026 AAGE Conference attendees</p></div></div><div ><div><p>Over 210 delegates have registered to attend the 2026 AAGE conference so far, including representatives from:</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p><strong>A</strong></p><p>ACCIONA, AEMO (Australian Energy Market Operator), Altus Financial, AMP, APA Group, ASC, Ashurst, Atlassian, Attorney-General''s Department, Australian Bureau of Statistics, Australian Communications and Media Authority, Australian Federal Police,&nbsp;Australian National Audit Office, Australian Submarine Agency,&nbsp;Australian Taxation Office, AustralianSuper</p><p><strong>B</strong></p><p>Babcock, BAE Systems Australia, BHP, Boeing Australia</p><p><strong>C</strong></p><p>Cement Australia, Chartered Accountants Australia and New Zealand, Clayton Utz, CommBank</p><p><strong>D</strong></p><p>DeakinTALENT, Department of Defence, Department of Energy, Environment and Climate Action (VIC), Department of Foreign Affairs and Trade,&nbsp;Department of Health, Disability and Ageing, Department of Social Services, Department of the Prime Minister and Cabinet, Department of the Treasury, DFP Recruitment, DLA Piper, Downer Group, DT Infrastructure</p><p><strong>E</strong></p><p>Evolution Mining, EY</p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><strong>F</strong></p><p>Forvis Maz