INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('sponsors-exhibitors', 'Sponsors and Exhibitors', '<div><div><div><div><table><tr><td><div><div><div ><div><h1>Meet the leading suppliers to the early talent industry</h1></div></div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td><td><div></div></td><td><div><div><div ><div></div></div></div></div></td></tr></table></div></div></div></div><!-- /content zone --><!-- footer zone --><div><div><div><div><table><tr><td><div><div><div ><div><p>AAGE Conference Sponsors and Exhibitors</p></div></div><div ><div><p>Becoming a sponsor or exhibitor at the AAGE Conference is a great way to position your company as a leading supplier to the sector, connect with early talent decision makers and showcase your products and services.</p><p><strong>2026 sponsorship and exhibitor opportunities will be available in April-May 2026.&nbsp;</strong></p></div></div></div></div></td></tr></table></div><div ><div><a href="mailto:conferencesponsorship@aage.com.au" target="_blank" rel="noopener">Enquire now about 2026 opportunities</a></div></div><div ><div><p>Thank you to our 2025 AAGE Conference Sponsors:</p></div></div><div><table><tr><td><div><div><div ><div><p><strong>Diamond Sponsor</strong></p></div></div><div ><div><p><a href="https://fusiongc.com.au/" target="_blank" target="_blank" rel="noopener"><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/0-1-fusion-92ceea09-17b78774.png" alt="" title="" loading="lazy"></a><br></p></div></div></div></div></td><td><div></div></td><td></td><td><div></div></td><td></td></tr></table></div><div ><div></div></div><div><table><tr><td><div><div><div ><div><p><strong>Gold Sponsors</strong></p></div></div><div ><div><a href="https://adelaideuni.edu.au/" target="_blank" target="_blank" rel="noopener"><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/1-0-adelaide-university-4