INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('2020-agrias-winners', '2020 AGRIAs Winners', '<div><div><div><div><table><tr><td><div><div><div ><div><h1>Recognising excellence in the early careers recruitment industry</h1></div></div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td><td><div></div></td><td></td></tr></table></div></div></div></div><!-- /content zone --><!-- footer zone --><div><div><div><div><table><tr><td><div><div><div ><div><p>Congratulations to the 2020 AGRIAs winners and finalists!</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p>Award for Best Graduate Employer <br></p></div></div><div ><div><p>(as determined by graduates participating in the 2020 AAGE Graduate Survey)</p><p>​<strong>WINNER:</strong>&nbsp;McGrathNicol</p><p><strong>FINALISTS:</strong>&nbsp;Australian Securities and Investments Commission, Sydney Water</p></div></div><div ><div><p>Award for Most Popular Supplier<br></p></div></div><div ><div><p>(as determined by employers participating in the 2020 AGRIAs voting process)</p><p><span><strong>WINNER:&nbsp;</strong>GradConnection</span></p><p><strong>FINALISTS:&nbsp;</strong>Prosple, Revelian</p></div></div><div ><div><p>Will Spensley Memorial Award for Innovation in the Graduate Market - Private Sector</p></div></div><div ><div><p>(as determined by AAGE employer members participating in the 2020 AGRIAs voting process)</p><p><strong>WINNER:</strong>&nbsp;Schneider Electric</p><p><strong>FINALISTS</strong>: Capgemini Australia. King &amp; Wood Mallesons (Agencies: InsideSherpa &amp; Unbnd Group), Xero</p><p>​To view all Will Spensley (Private Sector) Submissions, please <a href="https://www.agrias.com.au/copy-of-2020-innovation-private" target="_blank" target="_blank" rel="noopener">click here</a></p></div></div><div ><div><p>Will Spensley Memorial Award for Innovation in the Graduate Market - Public Sector</p></div></div><div ><div><p>(as determined by AAGE employer members participating in the 2020 AGRIAs voting process)</p><p><strong>WINNER:</strong>&nbsp;Teach For Australia</p><p>​<strong>FINALISTS:</strong>&nbsp;Australian Securities and Investments Commission, TasNetworks</p><p>​To view all Will Spensley (Public Sector) Submissions, please <a href="https://www.agrias.com.au/copy-of-2020-innovation-public" target="_blank" target="_blank" rel="noopener">click here</a></p></div></div><div ><div><p>Award for Best Internship Program <br></p></div></div><div ><div><p>(as determined by interns participating in the 2020 AAGE Intern Survey)</p><p><strong>WINNER:</strong>&nbsp;McGrathNicol</p><p><strong>FINALISTS:</strong>&nbsp;Atlassian, Xero</p></div></div><div ><div><p>Award for Best Graduate Development Program <br></p></div></div><div ><div><p>(as determined by graduates participating in the 2020 AAGE Graduate Survey)</p><p><span><strong>WINNER:&nbsp;</strong>McGrathNicol</span></p><p><strong>FINALISTS:&nbsp;</strong>AMP Services, Sydney Water</p></div></div><div ><div><p>Award for Most Popular Integrated Marketing Campaign - Public Sector<br></p></div></div><div ><div><p>(as determined by AAGE employer members participating in the 2020 AGRIAs voting process)</p><p></p><p><strong>WINNER:</strong>&nbsp;NSW Government (Agency: Percept Brand Design)</p><p>To view Winner and Finalists Integrated Marketing Campaign (Public Sector) Submissions, please <a href="https://www.agrias.com.au/copy-of-2020-integrated-mkg-public" target="_blank" target="_blank" rel="noopener">click here</a></p><p><strong>FINALISTS: </strong>Department of Defence (Agency: Swell Design Group), Teach For Australia (Agency: Tofu)</p></div></div><div ><div><p>Award for Most Popular Integrated Marketing Campaign - Private Sector<br></p></div></div><div ><div><p>(as determined by AAGE employer members participating in the 2020 AGRIAs voting process)</p><p><strong>WINNER:</strong>&nbsp;Aurecon</p><p><strong>FINALISTS:&nbsp;</strong>Arup, Atlassian (Agency: Instrument), Carlton &amp; United Breweries, Westpac Group (Agency: Havas People), Xero</p></div></div><div ><div> Award for Most Popular Careers Service</div></div><div ><div><p>(as determined by graduates participating in the 2020 AGRIAs voting process)</p><p><strong>WINNER:</strong><span>Deakin University</span></p><p><strong>FINALISTS:</strong>&nbsp;The University of Adelaide (Central Careers Service), The University of Queensland (Central Careers Service), University of Technology Sydney (Central Careers Service)</p></div></div><div ><div><p>Award for Most Popular Professional Association</p></div></div><div ><div> (as determined by employers participating in the 2020 AGRIAs voting process)<p></p><p><strong>WINNER</strong>:&nbsp;Chartered Accountants Australia and New Zealand</p><p><strong>FINALIST</strong>:&nbsp;Engineers Australia</p></div></div><div ><div><p>Award for Most Popular Graduate Recruiter<br></p></div></div><div ><div> as determined by candidates participating in the 2021 AAGE Candidate Survey) <p><strong>WINNER:</strong>&nbsp;Annalise Field (Deloitte)</p><p><strong>FINALISTS:&nbsp;</strong>Melanie Mathias (Deloitte), Samara Dunn (Deloitte)</p><p>​To view the Top 25 Graduate Recruiters please <a href="https://www.agrias.com.au/_files/ugd/8d3cb2_9eff5f1919634e259cf7b7d1cfb09a1c.pdf" target="_blank" target="_blank" rel="noopener">click here</a></p></div></div><div ><div><p>Award for Contribution to the Graduate Recruitment and Development Industry<br></p></div></div><div ><div><p>(as determined by employers participating in the 2020 AGRIAs voting process)</p><p><strong>WINNER:</strong>&nbsp;Domonique Delgado - GradConnection</p><p><strong>FINALISTS:&nbsp;</strong>David Cvetkovski - Fusion Graduate Consultancy, Jum Lamont - Fusion Graduate Consultancy, Sam McDonald - Prosple, Steven Nield - Aurecon</p></div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/agrias3-373px-e57698cc-efb29902.png" alt="" title="" loading="lazy"><br></p></div></div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/agrias1-373px-d997ae39-0580842c.png" alt="" title="" loading="lazy"><br></p></div></div><div ><div></div></div><div ><div></div></div><div ><div></div></div><div ><div></div></div><div ><div></div></div><div ><div></div></div><div ><div></div></div><div ><div></div></div><div ><div></div></div></div></div></td></tr></table></div><div ><div><p><br></p></div></div></div></div></div>', false, false, NULL, true);
