INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('2013-agrias-winners', '2013 AGRIAs Winners', '<div><div><div><div><table><tr><td><div><div><div ><div><h1>Recognising excellence in the early careers industry</h1></div></div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td><td><div></div></td><td></td></tr></table></div></div></div></div><!-- /content zone --><!-- footer zone --><div><div><div><div><table><tr><td><div><div><div ><div><p>Congratulations to the 2013 AGRIAs winners and finalists!</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p>Award for Most Popular Graduate Recruitment Video (private sector) <br></p></div></div><div ><div><p>(as determined by AAGE employer members participating in the 2013 AGRIAs voting process)</p><p><strong></strong></p><p><strong>WINNER: </strong>IBM (Agency: Twosocial - Social Media Agency)</p><p><strong>FINALISTS: </strong>BHP Billiton (Agency: 50 Kaliber) and <a href="https://www.youtube.com/watch?v=amnZLiBb4hM&list=PLxzd3ALKAWN_PBysLk_numKVfhcuwvNFu" target="_blank" target="_blank" rel="noopener">Lion</a> (Agency: Blaze Advertising)</p></div></div><div ><div><p>Award for Most Popular Graduate Recruitment Video (public sector)</p></div></div><div ><div><p>(as determined by AAGE employer members participating in the 2013 AGRIAs voting process)</p><p><strong></strong></p><p><strong>WINNER: </strong><a href="https://www.youtube.com/watch?v=QuMaQ13ck8I" target="_blank" target="_blank" rel="noopener">Sydney Water</a> (Agency: Pearshopinc)</p><p><strong>FINALISTS: </strong><a href="http://deewr.gov.au/videos/unfold-your-future-deewr" target="_blank" target="_blank" rel="noopener">Department of Education, Employment and Workplace Relations (DEEWR)</a> and Department of Environment and Heritage Protection (Qld)</p><p><strong></strong></p></div></div><div ><div><p>Award for