INSERT INTO pages (slug, title, content, requires_auth, show_in_nav, nav_position, published) VALUES ('2012-agrias-winners', '2012 AGRIAs Winners', '<div><div><div><div><table><tr><td><div><div><div ><div><h1>Recognising excellence in the early careers industry</h1></div></div><div ><div><a href="/page.html?slug=join-us" target="_blank" rel="noopener">Join us</a></div></div></div></div></td><td><div></div></td><td></td></tr></table></div></div></div></div><!-- /content zone --><!-- footer zone --><div><div><div><div><table><tr><td><div><div><div ><div><p>Congratulations to the 2012 AGRIAs winners and finalists!</p></div></div></div></div></td></tr></table></div><div><table><tr><td><div><div><div ><div><p>Award for Best Print Marketing Strategy (large organisations) <br></p></div></div><div ><div><p>(as voted by AAGE Members)</p><p><strong>WINNER: </strong>Xstrata Group (Wahoo Advertising)</p><p><strong>FINALISTS: </strong>Arrium - formerly OneSteel, Australian Taxation Office (ATO), Ernst &amp; Young</p></div></div><div ><div><p>Award for Best Print Marketing Strategy (small organisations)<br></p></div></div><div ><div><p>(as voted by AAGE Members)</p><p><strong>WINNER: </strong>Department of Finance and Deregulation</p><p><strong>FINALISTS:</strong> Lion, Public Service Commission - Queensland Government</p><p><strong></strong></p></div></div><div ><div><p>Award for Best Online Marketing Strategy (large organisations)<br></p></div></div><div ><div><p>(as voted by AAGE Members)</p><p><strong>WINNER: </strong>National Australia Bank (Blaze Advertising)</p><p><strong>FINALISTS: </strong>Arrium - formerly OneSteel, Deloitte, Telstra, Xstrata Group</p></div></div><div ><div><p>Award for Best Online Marketing Strategy (small organisations)<br></p></div></div><div ><div><p>(as voted by AAGE Members)</p><p><strong>WINNER: </strong>Public Service Commission &#8211; Queensland Government</p><p><strong>FINALISTS: </strong>Australian Prudential Regulation Authority (APRA), Department of Broadband, Communications and the Digital Economy</p></div></div><div ><div><p>Will Spensley Memorial Award for Innovation in the Graduate Market <br></p></div></div><div ><div><p>(as voted by our judging panel)</p><p><strong>WINNER: </strong>KPMG &#8211; New Zealand</p><p><strong>FINALISTS:</strong> Accenture, Deloitte</p></div></div><div ><div><p>Award for Best Graduate Development Program (large organisations) <br></p></div></div><div ><div><p>(as voted by our judging panel)</p><p><strong>WINNER: </strong>Australian Taxation Office (ATO)</p><p><strong>FINALISTS:</strong> BHP Billiton, BOC, Telstra</p><p><strong></strong></p></div></div><div ><div><p>Award for Best Graduate Development Program (small organisations)<br></p></div></div><div ><div><p>(as voted by our judging panel)</p><p><strong>WINNER: </strong>Teach for Australia</p><p><strong>FINALISTS:</strong> Attorney-General''s Department, Brisbane City Council</p><p><strong></strong></p></div></div><div ><div><p>Award for Best Careers Service for Employers</p></div></div><div ><div><p>(as voted by AAGE Members)</p><p><strong>WINNER: </strong>Monash University</p><p><strong>FINALISTS: </strong>The Australian National University, Curtin University of Technology</p><p><strong></strong></p></div></div><div ><div> Award for Most Innovative Supplier to the Graduate Recruitment Industry</div></div><div ><div><p>(as voted by AAGE Members)</p><p><strong>WINNER: </strong>GradConnection</p><p><strong>FINALISTS:</strong> Fusion, The Unimail Group</p></div></div><div ><div><p>Award for Best Employer of the Year<br></p></div></div><div ><div><p>(as voted by graduates participating in the 2012 AAGE Graduate Survey)</p><p><strong>WINNER: </strong>Reserve Bank of Australia</p><p><strong>FINALISTS:</strong> Australian Nuclear Science and Technology Organisation (ANSTO), Brisbane City Council, Department of Finance and Deregulation, SA Water Corporation</p></div></div><div ><div><p>Award for Best Internship Program<br></p></div></div><div ><div><p>(as voted by interns participating in the 2012 AAGE Intern Survey)</p><p><strong>WINNER: </strong>Chevron</p><p><strong>FINALISTS: </strong>ANZ, McGrath Nicol, PwC, Suncorp</p><p><strong></strong></p></div></div><div ><div><p>Award for Best Contribution to the Graduate Recruitment Industry<br></p></div></div><div ><div><p>(as voted by AAGE Members)</p><p><strong>WINNER: </strong>Daniel Purchas, GradConnection</p><p><strong>FINALISTS:</strong> Josh Mackenzie, DBL; Ben Reeves, Australian Association of Graduate Employers; Tim Watts, GradConnection NZ</p><p><strong></strong></p></div></div><div ><div><p>Award for Graduate Recruiter of the Year<br></p></div></div><div ><div><p>(as determined by 2013 AAGE Candidate Survey responses)</p><p><strong>WINNER: </strong>Stefanie Plummer, BHP Billiton</p><p><strong>FINALISTS:</strong> Daniel Lacey, Accenture; Elise Ianno, Commonwealth Bank; Farah Bayley, Shell</p><p><strong></strong></p></div></div><div ><div><p>Award for Best Exhibitor<br></p></div></div><div ><div><p>(as determined by 2012 AAGE Conference delegate votes)</p><p><strong>WINNER: </strong>GradConnection​</p></div></div><div ><div><p>AAGE Hall of Fame Award<br></p></div></div><div ><div><strong>RECIPIENT: </strong>Ainsley Gilkes</div></div></div></div></td><td><div></div></td><td><div><div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/agrias3-373px-e57698cc-efb29902.png" alt="" title="" loading="lazy"><br></p></div></div><div ><div><p><img src="https://pr-9q32ba.run402.com/_blob/assets/aage/agrias1-373px-d997ae39-0580842c.png" alt="" title="" loading="lazy"><br></p></div></div><div ><div></div></div><div ><div></div></div><div ><div></div></div><div ><div></div></div><div ><div></div></div><div ><div></div></div><div ><div></div></div><div ><div></div></div><div ><div></div></div></div></div></td></tr></table></div><div ><div><p><br></p></div></div></div></div></div>', false, false, NULL, true);
