INSERT INTO sections (page_slug, zone, scope, section_type, config, position, visible, column_span) VALUES ('index', 'main', 'page', 'hero', '{"mode":"background","heading":"Welcome to the home of the early careers industry in Australia","subheading":"","cta_text":"","cta_href":"","bg_image":"https://pr-9q32ba.run402.com/_blob/assets/aage/aage-inner-page-banner-1200-forupload-2-ce3c107d.png"}'::jsonb, 1, true, '1');
INSERT INTO sections (page_slug, zone, scope, section_type, config, position, visible, column_span) VALUES ('index', 'main', 'page', 'custom', '{"html":"<div>\n  <article>\n    <div><h2>Relationships</h2><p>Join our supportive community and connect with employers, universities, industry partners and talent.</p><a href=\"/page.html?slug=join-us\">Join us</a></div>\n    <div><img src=\"https://pr-9q32ba.run402.com/_blob/assets/aage/relationships-aage-homepage-7de483d7-d9f0ac23.png\" alt=\"AAGE relationships\" loading=\"lazy\" /></div>\n  </article>\n  <article>\n    <div><h2>Insights</h2><p>Make better informed decisions thanks to exclusive insights, information and market intelligence produced for AAGE members.</p><a href=\"/page.html?slug=knowledge\">AAGE Research</a></div>\n    <div><img src=\"https://pr-9q32ba.run402.com/_blob/assets/aage/insights-aage-homepage-c62ddfe9-001aef3c.png\" alt=\"AAGE insights\" loading=\"lazy\" /></div>\n  </article>\n  <article>\n    <div><h2>Expertise</h2><p>Share and recognise industry best practice in early careers talent programs.</p><a href=\"/page.html?slug=best-practice\">AAGE Awards</a></div>\n    <div><img src=\"https://pr-9q32ba.run402.com/_blob/assets/aage/homepage-gala-dinner-414bdb2c-f9951a9f.png\" alt=\"AAGE expertise\" loading=\"lazy\" /></div>\n  </article>\n  <article>\n    <div><h2>AAGE Events</h2><p>Develop your professional skills and enhance your graduate program by attending our events and conference.</p><a href=\"/page.html?slug=upcoming-events\">Upcoming Events</a></div>\n    <div><img src=\"https://pr-9q32ba.run402.com/_blob/assets/aage/events-aage-homepage-b1455a51-eac75c06.png\" alt=\"AAGE events\" loading=\"lazy\" /></div>\n  </article>\n</div>"}'::jsonb, 2, true, '1');
INSERT INTO sections (page_slug, zone, scope, section_type, config, position, visible, column_span) VALUES ('*', 'footer', 'global', 'custom', '{"html":"<div>\n  <div>\n    <div><h3>Contact Us</h3><p>Email: <a href=\"mailto:info@aage.com.au\">info@aage.com.au</a><br />Phone: <a href=\"tel:+61393525062\">+61 3 9352 5062</a><br />Address:<br />PO Box 1217<br />Camberwell VIC 3124 Australia</p></div>\n    <div><h3>Quick Links</h3><ul><li><a href=\"/\">Home</a></li><li><a href=\"/page.html?slug=join-us\">Join us</a></li><li><a href=\"/page.html?slug=member-zone\">Member Zone</a></li><li><a href=\"/events.html\">Events</a></li><li><a href=\"/page.html?slug=conference\">AAGE Conference</a></li></ul></div>\n    <div><h3>Related Websites</h3><ul><li><a href=\"https://startmycareer.com.au/\" target=\"_blank\" rel=\"noopener\">Start My Career</a></li><li><a href=\"https://www.thebigmeet.com.au/\" target=\"_blank\" rel=\"noopener\">The Big Meet</a></li><li><a href=\"https://startmycareer.com.au/Top-Graduate-Employers\" target=\"_blank\" rel=\"noopener\">Top Graduate Employers</a></li><li><a href=\"https://startmycareer.com.au/Top-Intern-Programs\" target=\"_blank\" rel=\"noopener\">Top Intern Programs</a></li></ul></div>\n  </div>\n  <div>© 2025 AAGE</div>\n</div>"}'::jsonb, 1, true, '1');
