INSERT INTO events (title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, created_by) VALUES ('2026 AAGE Guest Presentation and Member Discussion - Brisbane', 'This event series will include a panel of employers and presenters in each city, sharing insights about their programs and engaging in discussion on a range of topics in early careers talent acquisition and development. The presenters will be different in each state, however the format for each event will be similar. A networking lunch will enable you to catch up with industry peers, followed by a presentation of data from the 2026 AAGE Graduate and Intern Surveys. Our panel of speakers will be sourced from organisations rated as top employers based on feedback from these surveys and will explore candidate experience, onboarding and program structure, learning and development opportunities, and support for managers as well as give you an opportunity to ask questions. The session will conclude with an interactive discussion amongst attendees on the topics presented. This is an exciting opportunity to meet your peers from the graduate resourcing and development industry and learn more about topics such as: Building and delivering a best practice graduate program Employability and student engagement Graduate competency development Selection and the candidate experience. Brisbane guest speakers will include: Rasika Grice, Services Australia Todd Burmester, Stanwell Cost Complimentary entry for AAGE members. Non-members and member colleagues may attend for $50 + GST.    Members must be logged in to access complimentary registration. Cancellations In order for us to cater appropriately, please let us know if you need to cancel your attendance. Also, catering cannot be guaranteed if registration is made four days or less prior to the event. In order to cancel an invoice raised OR receive a refund for event attendance, the AAGE requires a MINIMUM of 24 hours'' notice to receive notice of your intention to cancel. All cancellation requests need to be received in writing via  events@aage.com.au . Enquiries Please contact  events@aage.com.au .
INSERT INTO events (title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, created_by) VALUES ('Graduate Managers Forum, Canberra - May 2026', 'Register You are invited to join us for the next Graduate Managers Forum (GMF) to discuss early careers in the Australian Public Service. Cost Complimentary entry for all attendees. Please note that this event is restricted to ACT-based Australian Government and University representatives only. Cancellations Please let us know if you need to cancel your attendance. The AAGE requires a MINIMUM of 24 hours'' notice to receive notice of your intention to cancel. All cancellation requests need to be received in writing via events@aage.com.au . Enquiries Please contact events@aage.com.au .
