INSERT INTO events (title, description, location, starts_at, ends_at, capacity, image_url, is_members_only, created_by) VALUES ('The Big Meet 2026, Perth - Exhibitor Booking', 'The Big Meet 2026, Perth - Exhibitor Booking When 01 Apr 2026   11:00 AM - 2:00 PM Location Pavilion 1, Perth Convention Exhibition Centre, 21 Mounts Bay Road, Perth, WA Registration (depends on selected options) Base fee: Member Registration - 1 Space (Single Space) – $2,650.00 This Last Chance Rate is for bookings made after Thursday 19th February 2026. Member Registration - 2 Spaces (Double Space) – $5,300.00 This Last Chance Rate is for bookings made after Thursday 19th February 2026. Member Registration - 3 Spaces (Triple Space) – $7,950.00 This Last Chance Rate is for bookings made after Thursday 19th February 2026. Non-Member Registration - 1 Space (Single Space) – $3,550.00 This Last Chance Rate is for bookings made after Thursday 19th February 2026. Non-Member Registration - 2 Spaces (Double Space) – $7,100.00 This Last Chance Rate is for bookings made after Thursday 19th February 2026. Non-Member Registration - 3 Spaces (Triple Space) – $10,650.00 This Last Chance Rate is for bookings made after Thursday 19th February 2026. We are pleased to offer organisations the opportunity to exhibit at The Big Meet 2026. What is The Big Meet? The Big Meet is a one day careers fair which is promoted to all students from all universities in the host city. Why Exhibit? The Big Meet provides the perfect solution for exhibitors wishing to maximise their exposure to potential candidates whilst minimising their costs. If you have limited time, resources or budget, The Big Meet is the ideal way to reach the right students from a range of universities in one day. Who Exhibits? To view previous years exhibitors, please visit:  www.thebigmeet.com.au  The Big Meet will be held in the following cities in 2026: Click the city name below to be taken to the booking form or to book all five cities at the bulk d